mapper.select:
Select TD.Name AS SRAreaLabelName From XBOLTAPP.ESM_SR_AREA TSA Left Outer Join XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) ON TD.TypeCode = TSA.ItemClassCode And TD.LanguageID = #{languageID} And TD.Category = 'CLS'
Left Outer Join XBOLTADM.TB_ITEM_CLASS TIC WITH(NOLOCK) ON TIC.ItemClassCode = TSA.ItemClassCode
Where SRTypeCode = #{srType} And TSA. Level = #{level}
AND TIC.ItemTypeCode = #{itemTypeCode}
Order By TSA.Level ASC

Select ItemProposalID 
  From XBOLTADM.TB_CR_MST 
 WHERE ItemID = #{itemID} 
       AND SRID = #{srID}


SELECT  TST.ItemTypeCode
  FROM  XBOLTAPP.ESM_SR_TYPE TST
 WHERE TST.SRTypeCode =  #{srType}

	 	SELECT
	 		Row_Number() OVER(ORDER BY  TE.SortNum, TI.IDENTIFIER ) AS RNUM 
	 		, TI.IDENTIFIER AS TypeCode
	 		, TIA.PlainText AS StsName
		  FROM XBOLTAPP.ESM_SR_MST TSC 
		       INNER JOIN XBOLTADM.TB_ELEMENT TE ON TSC.ProcPathID = TE.ModelID
		       INNER JOIN XBOLTADM.TB_ITEM TI ON TE.ObjectID = TI.ItemID And TE.ClassCode = #{itemClassCode}
      		   LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TI.ItemID = TIA.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID}
		 WHERE TSC.SRID = #{srID} 
		 And ISNULL(TI.IDENTIFIER,'') != '' AND TI.ClassCode = 'CL03004'
		 
		 	And ISNULL(TI.IDENTIFIER,'') = #{srStatus}
		 
		 ORDER BY  TE.SortNum ,TI.IDENTIFIER

Select ISNULL(SubCategory,Category) AS SRCatID
From XBOLTAPP.ESM_SR_MST
Where SRID = #{srID}

Select Top 1000 TBD.* From( Select Row_Number()OVER(ORDER BY TSM.SRID DESC) as RNUM, TSM.SRID, TSM.SRCode, TSM.SRType, TSM.ESType, TD5.Name AS SRTypeNM, TSM.ProcRoleTP, TSM.CustGRNo, TEAM6.Name AS CompanyName, TSM.ClientID, TSM.ProjectID, TPT.Name As ProjectName, TSM.Subject, TSM.Comment,TSM.Description, TSM.ProcPathID, TSM.SRArea1, TIA.PlainText As SRArea1Name, TSM.SRArea2, TIA2.PlainText As SRArea2Name, ISNULL(TSM.SRArea3,'0') AS SRArea3, TSM.Category, TD4.Name As CategoryNM, TSM.SubCategory, ISNULL(TD3.Name, TD4.Name) As SubCategoryNM, TSM.Priority, TD.Name As PriorityName, TSM.Status, TISA.PlainText As StatusName, TSM.RegUserID, TM2.Name As RegUserName, TSM.RegTeamID, TEAM1.Name As RegTeamName, ISNULL(CONVERT(char(10),TSM.RegDT, 120),'') as RegDate, TSM.RequestUserID, TM3.Name As ReqUserNM, TSM.RequestTeamID, TEAM2.Name As ReqTeamNM, ISNULL(CONVERT(char(10),TSM.DueDate, 120),'') as SRDueDate, ISNULL(CONVERT(char(10),TSM.ReqDueDate, 120),'') as ReqDueDate, TSM.ReceiptUserID, TM4.Name As ReceiptName, TD7.Name As SRReasonNM, TSM.ReceiptTeamID, TEAM3.Name As ReceiptTeamName, TM4.Name + '(' + TEAM3.Name + ')' as ReceiptInfo, TM3.Name + '(' + TEAM2.Name + ')' as RequestInfo, TSM.ResponseUserID, TM5.Name As ResponseUserName, TSM.ResponseTeamID, TEAM4.Name As ResponseTeamName, ISNULL(CONVERT(char(10),TSM.CompletionDT, 120),'') as SRCompletionDT,
TSM.RegDT As RegDTOrg, TSM.ReqDueDate AS ReqDueDateOrg, TSM.DueDate as DueDateOrg, TSM.CompletionDT As CompletionDTOrg, TSM.CompanyID, TSM.Classification As Classification, TSM.ReceiptTeamID As SRReceiptTeamID, Case When CompletionDT IS NULL Then 'N' Else 'Y' End AS SvcCompl, XBOLTAPP.fn_GetStartEventCode(TSM.SRID, TSM.ProcPathID) AS FirstSpeCode,
ReceiptDelay = CASE WHEN TSM.Duedate is null THEN CASE WHEN CONVERT(INT, DATEDIFF(HH, TSM.RegDT, GETDATE())) >= 12 THEN 'Y' ELSE 'N' END ELSE 'N' END, CompletionDelay = CASE WHEN TSM.CompletionDT is null THEN CASE WHEN TSM.Duedate < GETDATE() THEN 'Y' ELSE 'N' END WHEN TSM.CompletionDT is not null THEN CASE WHEN TSM.Duedate < tsm.CompletionDT THEN 'Y' ELSE 'N' END END, ISNULL(CONVERT(char(10),SRVIEW.MaxCRDueDate, 21),'') as CRDueDate, SRVIEW.CRReceiptTeamID, ISNULL(CONVERT(char(10),SRVIEW.maxCRCompletionDT, 21),'') as CRCompletionDT, TI.Identifier AS ItemCode, TIA3.PlainText AS ItemName, TSM.ItemTypeCode, ISNULL(TD2.Name, TD6.Name) AS ItemTypeCodeNM, TI.Identifier+' '+TIA3.PlainText+' ('+TIA.PlainText+'/'+TIA2.PlainText+')' AS ItemInfo, TIA.PlainText+'/'+TIA2.PlainText AS SRAreaNM, TD8.Name AS ProcRoleTypeName, XBOLTAPP.fn_GetESPRoleTPMemberList(TSM.ProcRoleTP, CASE WHEN (TSM.SRArea2 IS NULL OR TSM.SRArea2 = '' OR TSM.SRArea2 = '0') THEN TSM.SRArea1 ELSE TSM.SRArea2 END ) AS ProcRoleTypeMemberList, TMT.Name AS RequestCompanyName, CASE WHEN ISNULL(TSM.ReceiptUserID,'') != '' THEN (Select Top 1 ISNULL(CONVERT(char(10),StartTime, 120),'') From XBOLTAPP.ESM_ACTIVITY_LOG Where PID = TSM.SRID ORDER BY ActivityLogID) ELSE NULL END AS ReceiptDate, CASE WHEN TSM.DueDate < GETDATE() AND TSM.CompletionDT IS NULL THEN DATEDIFF(DAY, TSM.DueDate, GETDATE()) WHEN TSM.CompletionDT IS NOT NULL THEN Case When DATEDIFF(DAY, TSM.CompletionDT, TSM.DueDate) IS NULL THEN 0 ELSE DATEDIFF(DAY, TSM.CompletionDT, TSM.DueDate) END ELSE 0 END AS CompletionDelayDays
From XBOLTAPP.ESM_SR_MST TSM Left Outer Join XBOLTADM.TB_MEMBER TM2 On TM2.MemberID = TSM.RegUserID Left Outer Join XBOLTADM.TB_MEMBER TM3 On TM3.MemberID = TSM.RequestUserID Left Outer Join XBOLTADM.TB_MEMBER TM4 On TM4.MemberID = TSM.ReceiptUserID Left Outer Join XBOLTADM.TB_MEMBER TM5 On TM5.MemberID = TSM.ResponseUserID Left Outer Join XBOLTADM.TB_PROJECT_TXT TPT ON TPT.ProjectID = TSM.ProjectID And TPT.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD4 On TD4.TypeCode = TSM.Category AND TD4.Category = 'SRCAT' And TD4.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD3 On TD3.TypeCode = TSM.SubCategory And TD3.Category = 'SRCAT' And TD3.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD On TD.TypeCode = TSM.Priority And TD.Category = 'PRT' And TD.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM TIS ON TSM.Status = TIS.Identifier Left Outer Join XBOLTADM.TB_ITEM_ATTR TISA ON TISA.ItemID = TIS.ItemID And TISA.AttrTypeCode = 'AT00001' And TISA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM1 ON TEAM1.TeamID = TSM.RegTeamID And TEAM1.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM2 ON TEAM2.TeamID = TSM.RequestTeamID And TEAM2.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM3 ON TEAM3.TeamID = TSM.ReceiptTeamID And TEAM3.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM4 ON TEAM4.TeamID = TSM.ResponseTeamID And TEAM4.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = TSM.SRArea1 And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 ON TIA2.ItemID = TSM.SRArea2 And TIA2.AttrTypeCode = 'AT00001' And TIA2.LanguageID = #{languageID} Left Outer Join XBOLTADM.OLM_SRSUMMARY_VIEW SRVIEW ON SRVIEW.SRID = TSM.SRID Left Outer Join XBOLTADM.TB_ITEM TI ON TSM.SRArea3 = TI.ItemID Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA3 ON TIA3.ItemID = TSM.SRArea3 And TIA3.AttrTypeCode = 'AT00001' And TIA3.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD2 On TD2.TypeCode = TSM.ItemTypeCode And TD2.Category = 'OJ' And TD2.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD5 On TD5.TypeCode = TSM.SRType And TD5.Category = 'SRTP' And TD5.LanguageID = #{languageID} Left Outer Join XBOLTAPP.ESM_SR_TYPE EST On EST.srtypecode = TSM.srtype Left Outer Join XBOLTADM.TB_DICTIONARY TD6 On TD6.TypeCode = EST.ItemTypeCode And TD6.Category = 'OJ' And TD6.LanguageID = #{languageID} Left Outer Join XBOLTAPP.CRM_CUST_MST CCM ON TSM.ClientID = CCM.CustomerNo Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM6 ON TEAM6.TeamID = CCM.TeamID And TEAM6.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD7 On TD7.TypeCode = TSM.Reason And TD7.Category = 'SRRSN' And TD7.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD8 On TD8.TypeCode = TSM.ProcRoleTP And TD8.Category = 'SRROLETP' And TD8.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_TEAM TM ON TM.TeamID = TSM.RequestTeamID Left Outer Join XBOLTAPP.CRM_CUST_MST CCM2 ON CCM2.CustomerNo = TM.ClientID Left Outer Join XBOLTADM.TB_TEAM_TXT TMT ON TMT.TeamID = CCM2.TeamID And TMT.LanguageID = #{languageID} ) AS TBD
AND TBD.ESType = #{esType}
AND TBD.SRType = #{srType}
AND #{loginUserId} In (RequestUserID, ReceiptUserID , RegUserID)
AND #{loginUserId} In (RequestUserID, ReceiptUserID)
AND TBD.ClientID = (Select ClientID from XBOLTADM.TB_MEMBER Where MemberID = #{loginUserId} )
AND TBD.SRID In (Select PID from XBOLTADM.TB_PROC_LOG where ActorID = #{loginUserId} and ActivityID = 'ACTP003')
AND #{myTeamId} In (TBD.RequestTeamID, TBD.ReceiptTeamID)
AND #{loginUserId} In (SELECT MemberID FROM XBOLTADM.TB_MY_ITEM WHERE ItemID = TBD.SRArea2 AND Assigned = '1')
And SvcCompl = 'N'
And SvcCompl = 'Y'
AND TBD.Status = #{srStatus}
AND TBD.Status IN (${srStatusArr})
AND TBD.ProjectID IN (Select ProjectID From XBOLTADM.TB_PROJECT Where RefPGID = #{refID} And ProjectType = 'PJT' )
AND TBD.ProjectID = #{refID}
AND TBD.ProjectID IN (Select ProjectID From XBOLTADM.TB_PJT_MEMBER_REL Where MemberID = #{loginUserId} AND Involved = '1' )
AND ReqUserNM like N'%'+#{requestUserName}+'%'
AND RegUserName like N'%'+#{regUserName}+'%'
AND ReceiptName like N'%'+#{receiptUserName}+'%'
AND CONVERT(varchar(10), TBD.RegDate, 120) BETWEEN #{regStartDate} AND #{regEndDate}
AND TBD.SRArea1 = #{srArea1}
AND TBD.SRArea2 = #{srArea2}
AND TBD.Category = #{category}
AND TBD.SubCategory = #{subCategory}
AND TBD.Priority = #{priority}
AND CONVERT(varchar(10), TBD.SRdueDate, 120) BETWEEN #{stSRDueDate} AND #{endSRDueDate}
AND CONVERT(varchar(10), TBD.CRdueDate, 120) BETWEEN #{stCRDueDate} AND #{endCRDueDate}
AND Convert(varchar(10),TBD.CompletionDT, 120) <= #{completionDT}
AND TBD.SRCode like N'%'+#{srCode}+'%'
AND TBD.SrID = #{srID}
AND TBD.RequestTeamID = #{requestTeam}
AND TBD.ResponseTeamID = #{responseTeamID}
AND TBD.SRReceiptTeamID = #{srReceiptTeam}
AND TBD.ReceiptDelay = #{receiptDelay}
AND TBD.CompletionDelay = #{completionDelay}
AND TBD.Subject like N'%'+#{subject}+'%'
AND #{itemID} IN (TBD.SRArea1, TBD.SRArea2, TBD.SRArea3)
AND Classification = #{classification}
AND TBD.RequestTeamID IN (${requestTeamList})
AND ( TBD.CompanyID IN (${companyList}) OR TBD.RequestTeamID IN (${companyList}) )
AND TBD.CustGRNo = #{custGRNo}
AND TBD.ClientID = #{custNo})
AND TBD.ClientID = #{clientID}
AND TBD.CompanyID IN (#{companyID})
AND TBD.ItemCode like N'%'+#{itemCode}+'%'
AND TBD.ItemName like N'%'+#{itemName}+'%'
AND TBD.ItemTypeCode = #{itemTypeCode}
AND TBD.SRID in (Select ToSRID From XBOLTAPP.ESM_SR_CXN Where FromSRID = #{fromSRID})
AND TBD.RNUM BETWEEN ((${pageNo}-1)*${LIST_PAGE_SCALE} + 1) AND (${pageNo}*${LIST_PAGE_SCALE})
Order By TBD.SRID DESC

SELECT RIGHT('000000' + CAST(ISNULL(MAX(CAST(SUBSTRING(SRCode, 10, LEN(SRCode) - 9) AS INT)) + 1, 1) AS VARCHAR(6)), 6)
FROM XBOLTAPP.ESM_SR_MST 
WHERE LEFT(SRCODE, 3) = #{srType}

mapper.insert:
	INSERT INTO XBOLTAPP.ESM_SR_MBR
           (SRID
           ,MemberID
           ,MbrTeamID
           ,SpeCode
           ,AssignmentType
           ,RoleType
           ,RoleDescription
           ,OrderNum
           ,Assigned
           ,AccessRight
           ,AssignedDate
           ,DeassignedDate
           ,Creator
           ,LastUpdated)
     VALUES
           (
		    #{SRID}
           , #{memberID} 
           , #{mbrTeamID}
           ,#{speCode}
           , #{assignmentType}
           , #{roleType}
           , #{roleDescription}
           , #{orderNum}
           , #{assigned}
           , #{accessRight}
           , GetDate()
           , GetDate()
           , #{creator}
           , GetDate()
		   )

mapper.select:
		Select
	 		TSM.SRID, TSM.SRCode, TSM.SRType,TSM.ESType, TD7.Name AS SRTypeName, TSM.ProcRoleTP,
			TSM.ClientID, TEAM8.Name As ClientName, TSM.CustGRNo, TSM.ProjectID, TPT.Name AS ProjectNM, XBOLTADM.fn_getMyAbsPathForProject(TSM.ProjectID, #{languageID}) AS Path,
			TSM.Subject, TSM.Description, TSM.Comment,
			TSM.ProcPathID, TSM.SRArea1, TSM.SRArea2,
			TIA.PlainText As SRArea1Name, TIA2.PlainText As SRArea2Name,
			 ISNULL(TSM.SRArea3,'0') AS SRArea3, TI.Identifier AS SRArea3Code, TIA3.PlainText As SRArea3Name,
			TSM.Category, TSM.SubCategory, TSM.Priority, TD4.Name As CategoryName,
			TD3.Name As SubCategoryName, TD.Name As PriorityName,
			
			TSM.Status, TD2.Name As StatusName, TSM.RegUserID,
			TM2.Name As RegUserName, TSM.RegTeamID, TEAM1.Name As RegTeamName,			
			ISNULL(CONVERT(char(19),TSM.RegDT, 120),'') as RegDate,
			
			TSM.RequestUserID, TM3.Name As ReqUserNM,
			TSM.RequestTeamID, TEAM2.Name As ReqTeamNM,		
			ISNULL(CONVERT(char(10),TSM.ReqDueDate, 120),'') as ReqDueDate,
			ISNULL(CONVERT(char(8),TSM.ReqDueDate, 108),'') as ReqDueDateTime,	
			
			TSM.ReceiptUserID, TM4.Name As ReceiptName,
			TSM.ReceiptTeamID, TEAM3.Name As ReceiptTeamName,
			CONVERT(char(10),TSM.DueDate, 120) as DueDate,
			CONVERT(char(8),TSM.DueDate, 108) AS DueDateTime,
			
			TSM.ResponseUserID, TM5.Name As ResponseUserName,	
			TSM.ResponseTeamID, TEAM4.Name As ResponseTeamName,				
			ISNULL(CONVERT(char(10),TSM.CompletionDT, 120),'') as CompletionDT,
			
			TM6.Name As Area2RManager, TEAM5.Name As Area2RTeamName,			
			TSM.Spoint, TSM.Opinion, SRCAT.RoleType, 	ISNULL(SRCAT2.ProcessType, SRCAT.ProcessType) as ProcessType,
			TSM.CompanyID, TEAM6.Name As CompanyName, TSM.ITSMIF , TSM.Proposal	, TD5.Name as ProposalStatusNM, 
			TSM.Classification, TD6.Name As ClassificationNM,
			TSM.CurWFInstanceID As WFInstanceID, TSM.EvalSheetID,
			
			TD8.Name AS SRArea1NM, TD9.Name AS SRArea2NM, TD8.Name +'/'+ TD9.Name AS System,
			TSM.Reason AS SRReason, TD10.Name AS SRReasonNM,
			SRCAT2.FixedPath,
			
			XBOLTAPP.fn_GetESPLastEventCode(TSM.SRID,TSM.Status,#{languageID}) AS LastSpeCode,
			
			SRTYPE.DefWFID,
			Case When CompletionDT IS NULL Then 'N' Else 'Y' End AS SvcCompl,
			TSM.Blocked,
			XBOLTADM.fn_GetMyAbsPathForList(TSM.SRArea3, #{languageID}) AS srArea3Path,
			TD1.Name AS ItemTypeCodeNM,
			SRTYPE.BoardMgtID,
			TSM.Opinion,
			TIA4.PlainText AS SRStatusName,
			SRTYPE.DocCategory ,
			TSM.isPublic
		From XBOLTAPP.ESM_SR_MST TSM WITH(NOLOCK)
		Left Outer Join XBOLTADM.TB_MEMBER TM2 WITH(NOLOCK) On TM2.MemberID = TSM.RegUserID 
		Left Outer Join XBOLTADM.TB_MEMBER TM3 WITH(NOLOCK) On TM3.MemberID = TSM.RequestUserID 
		Left Outer Join XBOLTADM.TB_MEMBER TM4 WITH(NOLOCK) On TM4.MemberID = TSM.ReceiptUserID 
		Left Outer Join XBOLTADM.TB_MEMBER TM5 WITH(NOLOCK) On TM5.MemberID = TSM.ResponseUserID 
		Left Outer Join XBOLTADM.TB_DICTIONARY TD2 WITH(NOLOCK) On TD2.TypeCode = TSM.Status And TD2.Category = 'SRSTS' And TD2.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM1 WITH(NOLOCK) ON TEAM1.TeamID = TSM.RegTeamID And TEAM1.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM2 WITH(NOLOCK) ON TEAM2.TeamID = TSM.RequestTeamID And TEAM2.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM3 WITH(NOLOCK) ON TEAM3.TeamID = TSM.ReceiptTeamID And TEAM3.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM4 WITH(NOLOCK) ON TEAM4.TeamID = TSM.ResponseTeamID And TEAM4.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD3 WITH(NOLOCK) On TD3.TypeCode = TSM.SubCategory And TD3.Category = 'SRCAT' And TD3.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) On TD.TypeCode = TSM.Priority And TD.Category = 'PRT' And TD.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD4 WITH(NOLOCK) On TD4.TypeCode = TSM.Category And TD4.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TSM.SRArea1 And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} 
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = TSM.SRArea2 And TIA2.AttrTypeCode = 'AT00001' And TIA2.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD5 WITH(NOLOCK) On TD5.TypeCode = TSM.Proposal And TD5.Category = 'PROPSSTS' And TD5.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD6 WITH(NOLOCK) On TD6.TypeCode = TSM.Classification And TD6.Category = 'SRCLS' And TD6.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD7 WITH(NOLOCK) On TD7.TypeCode = TSM.SRType And TD7.Category = 'SRTP' And TD7.LanguageID = #{languageID}		
		Left Outer Join 
		  (SELECT Max(Seq) As MaxSeq, AssignmentType, ItemID, RoleType, Assigned, COUNT(*) AS CountX
            FROM   XBOLTADM.TB_MY_ITEM WITH(NOLOCK)
            GROUP BY AssignmentType, ItemID, RoleType, Assigned ) AS TMYITM ON TMYITM.ItemID = TSM.SRArea2 And TMYITM.RoleType = 'R' And TMYITM.AssignmentType = 'SRROLETP' And TMYITM.Assigned = '1' 
		Left outer Join XBOLTADM.TB_MY_ITEM MYITM WITH(NOLOCK) on MYITM.Seq = TMYITM.MaxSeq
		Left Outer Join XBOLTADM.TB_MEMBER TM6 WITH(NOLOCK) On TM6.MemberID = MYITM.MemberID 
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM5 WITH(NOLOCK) ON TEAM5.TeamID = TM6.TeamID And TEAM5.LanguageID = #{languageID}
		
		Left Outer Join XBOLTAPP.ESM_SR_CAT SRCAT WITH(NOLOCK) On SRCAT.SRCatID = TSM.Category 
		Left Outer Join XBOLTAPP.ESM_SR_CAT SRCAT2 WITH(NOLOCK) On SRCAT2.SRCatID = TSM.SubCategory 
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM6 WITH(NOLOCK) ON TEAM6.TeamID = TSM.CompanyID And TEAM6.LanguageID = #{languageID}
		
		Left Outer Join XBOLTADM.TB_TEAM TEAM7 WITH(NOLOCK) ON TEAM7.ClientID = TSM.ClientID AND TEAM7.TeamType = '2'
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM8 WITH(NOLOCK) ON TEAM8.TeamID = TEAM7.TeamID And TEAM8.LanguageID = #{languageID}
		
		Left Outer Join XBOLTAPP.ESM_SR_AREA TSA1 WITH(NOLOCK) ON TSA1.SRTypeCode = TSM.SRType And TSA1.Level = 1
		Left Outer Join XBOLTAPP.ESM_SR_AREA TSA2 WITH(NOLOCK) ON TSA2.SRTypeCode = TSM.SRType And TSA2.Level = 2
		Left Outer Join XBOLTADM.TB_DICTIONARY TD8 WITH(NOLOCK) ON TD8.TypeCode = TSA1.ItemClassCode And TD8.Category = 'CLS' And TD8.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD9 WITH(NOLOCK) ON TD9.TypeCode = TSA2.ItemClassCode And TD9.Category = 'CLS' And TD9.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD10 WITH(NOLOCK) On TD10.TypeCode = TSM.Reason And TD10.Category = 'SRRSN' And TD10.LanguageID = #{languageID}
		Left Outer Join XBOLTAPP.ESM_SR_TYPE SRTYPE WITH(NOLOCK) ON SRTYPE.SRTypeCode = TSM.SRType
		Left Outer Join XBOLTADM.TB_ITEM TI WITH(NOLOCK) ON TSM.SRArea3 = TI.ItemID
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA3 WITH(NOLOCK) ON TIA3.ItemID = TSM.SRArea3 And TIA3.AttrTypeCode = 'AT00001' And TIA3.LanguageID  =  #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM TI2 WITH(NOLOCK) ON TSM.SRArea3 = TI2.ItemID
		Left Outer Join XBOLTADM.TB_DICTIONARY TD1 WITH(NOLOCK) On TD1.TypeCode = TSM.ItemTypeCode And TD1.Category = 'OJ' And TD1.LanguageID =  #{languageID}
		Left Outer Join XBOLTADM.TB_PROJECT_TXT TPT WITH(NOLOCK) On TSM.ProjectID = TPT.ProjectID And TPT.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM TI3 WITH(NOLOCK) ON TSM.Status = TI3.Identifier
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA4 WITH(NOLOCK) ON TIA4.ItemID = TI3.ItemID And TIA4.AttrTypeCode = 'AT00001' And TIA4.LanguageID  =  #{languageID}
		
		Where TSM.SRID = #{srID}		
		
			AND TSM.SRType = #{srType}
		
		
			AND TSM.ESType = #{esType}
		
		
			AND TSA1.ItemClassCode = #{srArea1ClsCode}
		
		
			AND TSA2.ItemClassCode = #{srArea2ClsCode}

		Select
	 		TSM.SRID, TSM.SRCode, TSM.SRType,TSM.ESType, TD7.Name AS SRTypeName, TSM.ProcRoleTP,
			TSM.ClientID, TEAM8.Name As ClientName, TSM.CustGRNo, TSM.ProjectID, TPT.Name AS ProjectNM, XBOLTADM.fn_getMyAbsPathForProject(TSM.ProjectID, #{languageID}) AS Path,
			TSM.Subject, TSM.Description, TSM.Comment,
			TSM.ProcPathID, TSM.SRArea1, TSM.SRArea2,
			TIA.PlainText As SRArea1Name, TIA2.PlainText As SRArea2Name,
			 ISNULL(TSM.SRArea3,'0') AS SRArea3, TI.Identifier AS SRArea3Code, TIA3.PlainText As SRArea3Name,
			TSM.Category, TSM.SubCategory, TSM.Priority, TD4.Name As CategoryName,
			TD3.Name As SubCategoryName, TD.Name As PriorityName,
			
			TSM.Status, TD2.Name As StatusName, TSM.RegUserID,
			TM2.Name As RegUserName, TSM.RegTeamID, TEAM1.Name As RegTeamName,			
			ISNULL(CONVERT(char(10),TSM.RegDT, 120),'') as RegDate,
			
			TSM.RequestUserID, TM3.Name As ReqUserNM,
			TSM.RequestTeamID, TEAM2.Name As ReqTeamNM,		
			ISNULL(CONVERT(char(10),TSM.ReqDueDate, 120),'') as ReqDueDate,
			ISNULL(CONVERT(char(8),TSM.ReqDueDate, 108),'') as ReqDueDateTime,	
			
			TSM.ReceiptUserID, TM4.Name As ReceiptName,
			TSM.ReceiptTeamID, TEAM3.Name As ReceiptTeamName,
			CONVERT(char(10),TSM.DueDate, 120) as DueDate,
			CONVERT(char(8),TSM.DueDate, 108) AS DueDateTime,
			
			TSM.ResponseUserID, TM5.Name As ResponseUserName,	
			TSM.ResponseTeamID, TEAM4.Name As ResponseTeamName,				
			ISNULL(CONVERT(char(10),TSM.CompletionDT, 120),'') as CompletionDT,
			
			TM6.Name As Area2RManager, TEAM5.Name As Area2RTeamName,			
			TSM.Spoint, TSM.Opinion, SRCAT.RoleType, 	ISNULL(SRCAT2.ProcessType, SRCAT.ProcessType) as ProcessType,
			TSM.CompanyID, TEAM6.Name As CompanyName, TSM.ITSMIF , TSM.Proposal	, TD5.Name as ProposalStatusNM, 
			TSM.Classification, TD6.Name As ClassificationNM,
			TSM.CurWFInstanceID As WFInstanceID, TSM.EvalSheetID,
			
			TD8.Name AS SRArea1NM, TD9.Name AS SRArea2NM, TD8.Name +'/'+ TD9.Name AS System,
			TSM.Reason AS SRReason, TD10.Name AS SRReasonNM,
			SRCAT2.FixedPath,
			
			XBOLTAPP.fn_GetESPLastEventCode(TSM.SRID,TSM.Status,#{languageID}) AS LastSpeCode,
			
			SRTYPE.DefWFID,
			Case When CompletionDT IS NULL Then 'N' Else 'Y' End AS SvcCompl,
			TSM.Blocked,
			XBOLTADM.fn_GetMyAbsPathForList(TSM.SRArea3, #{languageID}) AS srArea3Path,
			TD1.Name AS ItemTypeCodeNM,
			SRTYPE.BoardMgtID,
			TSM.Opinion,
			TIA4.PlainText AS SRStatusName,
			SRTYPE.DocCategory ,
			TSM.isPublic
		From XBOLTAPP.ESM_SR_MST TSM
		Left Outer Join XBOLTADM.TB_MEMBER TM2 On TM2.MemberID = TSM.RegUserID 
		Left Outer Join XBOLTADM.TB_MEMBER TM3 On TM3.MemberID = TSM.RequestUserID 
		Left Outer Join XBOLTADM.TB_MEMBER TM4 On TM4.MemberID = TSM.ReceiptUserID 
		Left Outer Join XBOLTADM.TB_MEMBER TM5 On TM5.MemberID = TSM.ResponseUserID 
		Left Outer Join XBOLTADM.TB_DICTIONARY TD2 On TD2.TypeCode = TSM.Status And TD2.Category = 'SRSTS' And TD2.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM1 ON TEAM1.TeamID = TSM.RegTeamID And TEAM1.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM2 ON TEAM2.TeamID = TSM.RequestTeamID And TEAM2.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM3 ON TEAM3.TeamID = TSM.ReceiptTeamID And TEAM3.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM4 ON TEAM4.TeamID = TSM.ResponseTeamID And TEAM4.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD3 On TD3.TypeCode = TSM.SubCategory And TD3.Category = 'SRCAT' And TD3.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD On TD.TypeCode = TSM.Priority And TD.Category = 'PRT' And TD.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD4 On TD4.TypeCode = TSM.Category And TD4.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = TSM.SRArea1 And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} 
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 ON TIA2.ItemID = TSM.SRArea2 And TIA2.AttrTypeCode = 'AT00001' And TIA2.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD5 On TD5.TypeCode = TSM.Proposal And TD5.Category = 'PROPSSTS' And TD5.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD6 On TD6.TypeCode = TSM.Classification And TD6.Category = 'SRCLS' And TD6.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD7 On TD7.TypeCode = TSM.SRType And TD7.Category = 'SRTP' And TD7.LanguageID = #{languageID}		
		Left Outer Join 
		  (SELECT Max(Seq) As MaxSeq, AssignmentType, ItemID, RoleType, Assigned, COUNT(*) AS CountX
            FROM   XBOLTADM.TB_MY_ITEM
            GROUP BY AssignmentType, ItemID, RoleType, Assigned ) AS TMYITM ON TMYITM.ItemID = TSM.SRArea2 And TMYITM.RoleType = 'R' And TMYITM.AssignmentType = 'SRROLETP' And TMYITM.Assigned = '1' 
		Left outer Join XBOLTADM.TB_MY_ITEM MYITM on MYITM.Seq = TMYITM.MaxSeq
		Left Outer Join XBOLTADM.TB_MEMBER TM6 On TM6.MemberID = MYITM.MemberID 
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM5 ON TEAM5.TeamID = TM6.TeamID And TEAM5.LanguageID = #{languageID}
		
		Left Outer Join XBOLTAPP.ESM_SR_CAT SRCAT On SRCAT.SRCatID = TSM.Category 
		Left Outer Join XBOLTAPP.ESM_SR_CAT SRCAT2 On SRCAT2.SRCatID = TSM.SubCategory 
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM6 ON TEAM6.TeamID = TSM.CompanyID And TEAM6.LanguageID = #{languageID}
		
		Left Outer Join XBOLTADM.TB_TEAM TEAM7 ON TEAM7.ClientID = TSM.ClientID AND TEAM7.TeamType = '2'
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM8 ON TEAM8.TeamID = TEAM7.TeamID And TEAM8.LanguageID = #{languageID}
		
		Left Outer Join XBOLTAPP.ESM_SR_AREA TSA1 ON TSA1.SRTypeCode = TSM.SRType And TSA1.Level = 1
		Left Outer Join XBOLTAPP.ESM_SR_AREA TSA2 ON TSA2.SRTypeCode = TSM.SRType And TSA2.Level = 2
		Left Outer Join XBOLTADM.TB_DICTIONARY TD8 ON TD8.TypeCode = TSA1.ItemClassCode And TD8.Category = 'CLS' And TD8.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD9 ON TD9.TypeCode = TSA2.ItemClassCode And TD9.Category = 'CLS' And TD9.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD10 On TD10.TypeCode = TSM.Reason And TD10.Category = 'SRRSN' And TD10.LanguageID = #{languageID}
		Left Outer Join XBOLTAPP.ESM_SR_TYPE SRTYPE ON SRTYPE.SRTypeCode = TSM.SRType
		Left Outer Join XBOLTADM.TB_ITEM TI ON TSM.SRArea3 = TI.ItemID
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA3 ON TIA3.ItemID = TSM.SRArea3 And TIA3.AttrTypeCode = 'AT00001' And TIA3.LanguageID  =  #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM TI2 ON TSM.SRArea3 = TI2.ItemID
		Left Outer Join XBOLTADM.TB_DICTIONARY TD1 On TD1.TypeCode = TSM.ItemTypeCode And TD1.Category = 'OJ' And TD1.LanguageID =  #{languageID}
		Left Outer Join XBOLTADM.TB_PROJECT_TXT TPT On TSM.ProjectID = TPT.ProjectID And TPT.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM TI3 ON TSM.Status = TI3.Identifier
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA4 ON TIA4.ItemID = TI3.ItemID And TIA4.AttrTypeCode = 'AT00001' And TIA4.LanguageID  =  #{languageID}
		
		Where TSM.SRID = #{srID}		
		
			AND TSM.SRType = #{srType}
		
		
			AND TSM.ESType = #{esType}
		
		
			AND TSA1.ItemClassCode = #{srArea1ClsCode}
		
		
			AND TSA2.ItemClassCode = #{srArea2ClsCode}

 	SELECT distinct SRArea1ITM.ItemID AS CODE
	  ,SRArea1ATR.PlainText AS NAME	
	  ,ITM.Identifier	
	FROM XBOLTADM.TB_ITEM_ATTR SRType WITH(NOLOCK)
	INNER JOIN XBOLTADM.TB_ITEM_ATTR SRArea1ITM WITH(NOLOCK) ON SRType.ItemID = SRArea1ITM.ItemID AND SRArea1ITM.LovCode = 'LV38001' 
	INNER JOIN XBOLTADM.TB_ITEM_ATTR SRArea1ATR WITH(NOLOCK) ON SRArea1ITM.ItemID = SRArea1ATR.ItemID AND SRArea1ATR.AttrTypeCode  = 'AT00001' AND SRArea1ATR.LanguageID = #{languageID} 
	INNER JOIN XBOLTADM.TB_ITEM ITM WITH(NOLOCK) ON SRArea1ATR.ItemID = ITM.ItemID And ITM.Deleted != 1
 		
			INNER JOIN XBOLTAPP.ESM_SR_MST  TSM
	 		ON TSM.SRArea1 = SRType.ItemID
	 		AND TSM.ReceiptTeamID = #{receiptTeam} 
		
	Where SRType.AttrTypeCode = 'AT00036'  
	And SRType.PlainText = #{srType} 
	
	And SRType.ItemTypeCode = #{itemTypeCode}
	
	
	And ITM.ClientID = #{customerNo}
	
	Order by NAME

		Select 
			   TSC.SRCatID AS CODE, TD.Name AS NAME 
		From XBOLTAPP.ESM_SR_CAT TSC WITH(NOLOCK)
		Left Outer Join XBOLTADM.TB_DICTIONARY TD  WITH(NOLOCK) ON TD.TypeCode  = TSC.SRCatID And TD.Category = 'SRCAT' And TD.LanguageID = #{languageID}
		
		Left Outer Join XBOLTAPP.ESM_SR_CAT_CFG ESCC WITH(NOLOCK) ON TSC.SRCatID = ESCC.SRCatID
		
		Where TSC.SRType = #{srType}
		
			AND TSC.Level = #{level}
		
 		
			AND TSC.ParentID = #{parentID} 
		
		
			AND TSC.itemTypeCode IN (#{itemTypeCode},'')
		
		
			AND ESCC.ClientID = #{customerNo}

		SELECT DISTINCT TI.IDENTIFIER AS CODE, TIA.PlainText AS NAME , TE.SortNum
		  FROM XBOLTAPP.ESM_SR_TYPE TST WITH(NOLOCK)
		       INNER JOIN XBOLTADM.TB_ELEMENT TE WITH(NOLOCK) ON TST.ProcModelID = TE.ModelID
		       INNER JOIN XBOLTADM.TB_ITEM TI WITH(NOLOCK) ON TE.Link = TI.ItemID and TI.ClassCode = #{itemClassCode}
      		   INNER JOIN XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TI.ItemID = TIA.ItemID and TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
  		  WHERE 1=1
  		  
  		  And TST.SRTypeCode = #{srType}
  		  
		  And ISNULL(TI.Identifier,'') != '' 
		  ORDER BY  TE.SortNum , TI.Identifier

SELECT Distinct SRMST.ReceiptTeamID AS CODE , TMT.Name AS NAME FROM XBOLTAPP.ESM_SR_MST SRMST WITH(NOLOCK) INNER Join XBOLTADM.TB_TEAM_TXT TMT WITH(NOLOCK) on SRMST.ReceiptTeamID = TMT.TeamID AND TMT.LanguageID = #{languageID}
And SRMST.srType = #{srType}
AND SRMST.SRID in (Select ToSRID From XBOLTAPP.ESM_SR_CXN WITH(NOLOCK) Where FromSRID = #{fromSRID})
ORDER BY NAME

Select 
	Top 1 TMI.MemberID, TM.TeamID As TeamID
From XBOLTADM.TB_MY_ITEM TMI  
Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TMI.MemberID
Left Outer Join XBOLTADM.TB_TEAM_TXT TXT ON TXT.TeamID = TM.TeamID And TXT.LanguageID = #{languageID}
Where TMI.ItemID = #{itemID} 
And TMI.RoleType = #{roleType} 
And TMI.AssignmentType = #{assignmentType} 
And TMI.Assigned = '1' 
Order By TMI.OrderNum ASC

Select 
	TMI.MemberID
	, TM.TeamID As TeamID
	, TMI.RoleType 
	, TM.Name+'(' + TXT.Name + ')' AS WFStep
From XBOLTADM.TB_MY_ITEM TMI  
Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TMI.MemberID
Left Outer Join XBOLTADM.TB_TEAM_TXT TXT ON TXT.TeamID = TM.TeamID And TXT.LanguageID = #{languageID}
Where TMI.ItemID = #{itemID} 
And TMI.RoleType = #{roleType} 
And TMI.AssignmentType = #{assignmentType} 
And TMI.Assigned = '1' 
Order By TMI.OrderNum ASC

SELECT 
	Distinct ESMSR.RequestTeamID AS CODE
	, TMT.Name AS NAME
FROM 
	XBOLTAPP.ESM_SR_MST ESMSR
	, XBOLTADM.TB_TEAM TM 
	Left Outer Join XBOLTADM.TB_TEAM_TXT TMT ON TM.TeamID = TMT.TeamID AND TMT.LanguageID = #{languageID}
	Where TM.TeamID = ESMSR.RequestTeamID
	
		And TM.ParentID IN (${parentIDs})
	
	
		And ESMSR.srType = #{srType}
	
	
		And ESMSR.SRArea3 = #{itemID}
	
	
		AND ESMSR.SRID in (Select ToSRID From XBOLTAPP.ESM_SR_CXN Where FromSRID = #{fromSRID})
	
	
		And TM.CompanyID = #{companyID}
	
	
		And ESMSR.ClientID = #{customerNo}
	
ORDER BY NAME

Select 
	TM.Name + '('+ISNULL(TMT.Name,'-')+')' AS esmSRMbr
From XBOLTAPP.ESM_SR_MBR ESM WITH(NOLOCK)
Left Outer Join XBOLTADM.TB_MEMBER TM WITH(NOLOCK) ON TM.MemberID = ESM.MemberID 
Left Outer Join XBOLTADM.TB_TEAM_TXT TMT WITH(NOLOCK) ON TMT.TeamID = TM.TeamID And TMT.LanguageID = #{languageID}
Where ESM.SRID = #{srID}

     	Select TBM.MemberID, TM.Name + '('+ISNULL(TMXT.Name,'-')+')' AS SRRefMember
		From XBOLTAPP.ESM_SR_MBR TBM WITH(NOLOCK)
		Left Outer Join XBOLTADM.TB_MEMBER TM WITH(NOLOCK) ON TM.MemberID = TBM.MemberID 
		Left OUter Join XBOLTADM.TB_TEAM_TXT TMXT WITH(NOLOCK) ON TMXT.TeamID = TM.TeamID And TMXT.LanguageID = #{languageID}
		Where TBM.SRID = #{SRID}
		
			And TBM.RoleType = #{roleType}
		
		
			And TBM.AssignmentType = #{assignmentType}
		
		
			And TBM.MemberID = #{memberID}

mapper.delete:
     	Delete From XBOLTAPP.ESM_SR_MBR
		Where SRID = #{SRID}
		And RoleType = #{roleType}
		And AssignmentType = #{assignmentType}
		
			And MemberID Not IN (${memberIDs})
		
		
			And MemberID = #{memberID}
		
		
			And SpeCode = #{speCode}

mapper.select:
Select SRArea2	
From XBOLTAPP.ESM_SR_MST ESM
Where SRID = #{srID}

Select TI.Identifier AS elmCode
From XBOLTADM.TB_ELEMENT TE	INNER JOIN XBOLTADM.TB_ITEM TI ON TE.Link = TI.ItemID		
Where TE.ModelID = #{procPathID} 	

	 And TI.ItemTypeCode = #{elmItemTypeCode}
 

	And TI.ClassCode = #{elmClassCode}

  		Select
			Distinct TI.ItemID AS CODE, TI.Identifier + ' ' + TIA.PlainText AS NAME
		From XBOLTADM.TB_ITEM TI
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA ON TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
		Left Outer Join XBOLTAPP.ESM_SR_AREA ESA ON TI.ClassCode = ESA.ItemClassCode 
		Where ESA.SRTypeCode = #{srType}
		AND ESA.ItemTypeCode = #{itemTypeCode}
		AND ESA.Level = #{level}
		AND TI.CategoryCode = 'OJ' AND TI.Deleted != 1
		
			AND TI.ItemID in (Select ToItemID From XBOLTADM.TB_ITEM Where FromItemID = #{srArea1})
		
		Order by NAME

Select
	ESA.ItemClassCode
FROM XBOLTAPP.ESM_SR_AREA ESA
Left Outer Join XBOLTADM.TB_ITEM_CLASS TIC WITH(NOLOCK) ON ESA.ItemClassCode = TIC.ItemClassCode
Where ESA.SRTypeCode = #{srType}

AND TIC.ItemTypeCode = #{itemTypeCode}

AND ESA.Level = #{level}

  		  Select 
			Distinct TIT.ItemTypeCode AS CODE, TD.Name AS NAME
		  From XBOLTADM.TB_ITEM_TYPE TIT
		  Left Outer Join XBOLTADM.TB_DICTIONARY TD ON TIT.ItemTypeCode = TD.TypeCode AND TD.LanguageID =#{languageID}
		  Where TIT.DefSRType = #{srType}
		  And TIT.Deactivated != 1

   Select
	ESC.ManagerID AS AuthorID, TM.TeamID AS OwnerTeamID
  From XBOLTAPP.ESM_SR_CAT ESC
  Left Outer Join XBOLTADM.TB_MEMBER TM ON ESC.ManagerID = TM.MemberID
  Where ESC.SRType = #{srType}
  and ESC.SRCatID = #{srCatID}

Select ESCA.SRCatID , ESCA.SortNum , ESCA.AttrTypeCode AS AttrTypeCode , ISNULL(TD.Name, '') AS AttrTypeName , ESCA.ItemTypeCode , ESCA.SortNum , ESCA.AreaHeight , ESCA.RowNum , ESCA.ColumnNum , ISNULL(ESCA.DefaultValue,'') AS DefaultValue , ISNULL(ESA.Value, ISNULL(ESCA.DefaultValue,'')) AS Value , ESA.LovCode , TAT.DataType , TAT.HTML , ISNULL(ESCA.Mandatory,'') AS Mandatory From XBOLTAPP.ESM_SR_CAT_ATTR ESCA Left Outer Join XBOLTAPP.ESM_SR_ATTR ESA ON ESA.AttrTypeCode = ESCA.AttrTypeCode And ESA.SRID = #{srID} And ESA.AttrTypeCode NOT IN(Select AttrTypeCode From XBOLTADM.TB_ATTR_TYPE Where DataType = 'MLOV') Left Outer Join XBOLTADM.TB_DICTIONARY TD ON TD.TypeCode = ESCA.AttrTypeCode And TD.LanguageID = #{languageID} And TD.Category = 'AT' Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT ON TAT.AttrTypeCode = ESCA.AttrTypeCode Where ESCA.SRCatID = #{SRCatID}
And ESCA.SpeCode = #{speCode}
Order By ESCA.SortNum ASC

mapper.insert:
	INSERT INTO 
	
		 XBOLTAPP.ESM_SCR_ATTR 
		 XBOLTAPP.ESM_WKS_ATTR 
		 XBOLTAPP.ESM_SR_ATTR 
	
          ( 
          
			 SCRID 
			 SRID 
		  
           , AttrTypeCode
           , Value
           , LovCode
           , SpeCode
           , Creator
           , CreationTime
           , LastUser
           , LastUpdated 
     ) VALUES
           ( 
            
				 #{scrID} 
				 #{srID} 
		  	
           , #{attrTypeCode}
           , #{value}
           , #{lovCode}
           , #{speCode}
           , #{userID}
           , GetDate()
           , #{userID}
           , GetDate() )

	INSERT INTO XBOLTAPP.ESM_SR_ATTR_REV
          (  ActivitySeq
           , SRID
           , ActivityLogID
           , AttrTypeCode
           , Value
           , LovCode
           , SpeCode
           , Creator
           , CreationTime
           , LastUser
           , LastUpdated 
     ) VALUES
           ( #{activitySeq}
           , #{srID}
           , #{activityLogID}
           , #{attrTypeCode}
           , #{value}
           , #{lovCode}
           , #{speCode}
           , #{userID}
           , GetDate()
           , #{userID}
           , GetDate() )

mapper.delete:
     	Delete From 
     	
			 XBOLTAPP.ESM_SCR_ATTR 
			 XBOLTAPP.ESM_WKS_ATTR 
			 XBOLTAPP.ESM_SR_ATTR 
		
     	Where SRID = #{srID}
     	 And AttrTypeCode = #{attrTypeCode}
     	 
				And SpeCode = #{speCode}

mapper.select:
Select Count(*) From XBOLTAPP.ESM_SR_MST
SRType = #{srType}
AND #{loginUserId} In (RequestUserID, ReceiptUserID , RegUserID)
And ISNULL(CompletionDT,'') = ''
And ISNULL(CompletionDT,'') != ''
AND Status = #{srStatus}

SELECT Distinct SRMST.ResponseTeamID AS CODE , TMT.Name AS NAME FROM XBOLTAPP.ESM_SR_MST SRMST Left Outer Join XBOLTADM.TB_TEAM_TXT TMT on SRMST.ResponseTeamID = TMT.TeamID AND TMT.LanguageID = #{languageID}
And SRMST.srType = #{srType}
And ISNULL(SRMST.ResponseTeamID,'') != '' ORDER BY NAME

	select 'N/A' label, ESM.Reason code, Count(*) value 
	from XBOLTAPP.ESM_SR_MST ESM
	WHERE ESM.Reason IS NULL
		 
		AND SRArea1 = #{srArea1} 
	 
	 
		AND YEAR(CONVERT(DATETIME,ESM.RegDT)) = #{year}
	
	 
		AND MONTH(CONVERT(DATETIME,ESM.RegDT)) = #{month}
	
	GROUP BY ESM.Reason

	UNION

	SELECT TD.Name AS label, td.TypeCode AS code, COUNT(ESM.SRID) AS value
	FROM XBOLTADM.TB_DICTIONARY TD
	LEFT JOIN XBOLTAPP.ESM_SR_MST ESM ON TD.TypeCode = ESM.Reason
 		 
		AND ESM.SRArea1 = #{srArea1} 
	  
	 
		AND YEAR(CONVERT(DATETIME,ESM.RegDT)) = #{year}
	
	 
		AND MONTH(CONVERT(DATETIME,ESM.RegDT)) = #{month}
	
	WHERE TD.Category = 'SRRSN' AND TD.LanguageID = #{languageID}
	GROUP BY TD.NAME, td.TypeCode

	ORDER BY code

		SELECT 
			CASE WHEN ITSMIF IS NULL THEN 'N/A'
			ELSE ITSMIF END label,
			ITSMIF code,
			COUNT(SRID) value
		FROM XBOLTAPP.ESM_SR_MST
					
  				
				AND SRArea1 = #{srArea1}
				
			
				AND YEAR(CONVERT(DATETIME,RegDT)) = #{year}
			
			 
				AND MONTH(CONVERT(DATETIME,RegDT)) = #{month}
			
		
		Group by ITSMIF

SELECT ESM.ReceiptUserID AS CODE , TM.Name AS NAME FROM XBOLTAPP.ESM_SR_MST ESM Left Outer Join XBOLTADM.TB_MEMBER TM on ESM.ReceiptUserID = TM.MemberID
And ESM.srType = #{srType}
And ISNULL(ESM.ReceiptUserID,'') != '' GROUP BY ESM.ReceiptUserID , TM.Name ORDER BY TM.NAME

SELECT ESM.ReceiptTeamID AS CODE , TXT.Name AS NAME FROM XBOLTAPP.ESM_SR_MST ESM Left Outer Join XBOLTADM.TB_TEAM_TXT TXT on ESM.ReceiptTeamID = TXT.TeamID and TXT.LanguageID = #{languageID}
And ESM.srType = #{srType}
And ISNULL(ESM.ReceiptTeamID,'') != '' GROUP BY TXT.Name , ESM.ReceiptTeamID ORDER BY TXT.NAME

SELECT ESM.SRCode, ESM.Subject, TM.Name + '(' + TT.Name + ')' as RequestUserNM, ATR.PlainText as SRArea1NM, TM2.Name + '(' + TT2.Name + ')' as ReceiptUserNM, Convert(char(10),ESM.RegDT, 21) as RegDT, Convert(char(10),ESM.CompletionDT, 21) as CompletionDT, EEIV.Total, CASE WHEN EEIV.Total >= 91 THEN '05' WHEN EEIV.Total BETWEEN 81 AND 90 THEN '04' WHEN EEIV.Total BETWEEN 61 AND 80 THEN '03' WHEN EEIV.Total BETWEEN 51 AND 60 THEN '02' ELSE '01' END as Result, ESM.SRID FROM XBOLTAPP.ESM_SR_MST ESM LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TM.MemberID = ESM.RequestUserID LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM2 ON TM2.MemberID = ESM.ReceiptUserID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT ON TT.TeamID = ESM.RequestTeamID AND TT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT2 ON TT2.TeamID = ESM.ReceiptTeamID AND TT2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR ATR ON ATR.ItemID = ESM.SRArea1 AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTAPP.ESM_EVAL_SHEET EES ON EES.DocumentID = ESM.SRID INNER JOIN ( SELECT EI.EvalSheetID, SUM(CONVERT(Integer, Value)) Total FROM XBOLTAPP.ESM_EVAL_ITEM_VALUE EI LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE AT ON AT.AttrTypeCode = EI.AttrTypeCode WHERE AT.DataType = 'LOV' GROUP BY EvalSheetID ) EEIV ON EEIV.EvalSheetID = EES.EvalSheetID
WHERE ESM.Status = 'ISP008'
AND ESM.SRArea1 = #{srArea1}
AND ESM.RegDT >= #{startDate}
AND ESM.RegDT <= #{endDate}

SELECT
ISNULL(Avg(A.Total),0)
Count(A.Total)
FROM ( SELECT EI.EvalSheetID, SUM(CONVERT(Integer, EI.Value)) Total FROM XBOLTAPP.ESM_EVAL_ITEM_VALUE EI LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE AT ON AT.AttrTypeCode = EI.AttrTypeCode LEFT OUTER JOIN XBOLTAPP.ESM_EVAL_SHEET EES ON EES.EvalSheetID = EI.EvalSheetID LEFT OUTER JOIN XBOLTAPP.ESM_SR_MST ESM ON ESM.EvalSheetID = EI.EvalSheetID AND ESM.SRID = EES.DocumentID WHERE AT.DataType = 'LOV'
AND ESM.SRArea1 = #{srArea1}
AND ESM.ReceiptUserID = #{receiptUserID}
AND ESM.ReceiptTeamID = #{receiptTeamID}
AND YEAR(CONVERT(DATETIME,ESM.CompletionDT)) = #{year}
AND MONTH(CONVERT(DATETIME,ESM.CompletionDT)) = #{month}
GROUP BY EI.EvalSheetID ) A
A.Total >= 91 A.Total BETWEEN 81 AND 90 A.Total BETWEEN 61 AND 80 A.Total BETWEEN 51 AND 60 A.Total <= 50

