	ReceiptUserID = null,
	ReceiptTeamID = null,
	LastUpdated = GETDATE(),
	LastUser = #{lastUser}			
Where SRID = #{srID}

mapper.select:
SELECT XBOLTAPP.fn_GetESPPreEventCode(#{srID},#{status},#{sortNum}) From XBOLTAPP.ESM_SR_MST ESM WITH(NOLOCK)

	LEFT OUTER JOIN XBOLTAPP.ESM_ACTIVITY_LOG EAL WITH(NOLOCK) ON EAL.PID = ESM.SRID AND EAL.SpeCode = #{status} AND EAL.Seq = #{seq}

 Where SRID = #{srID}
 
 	AND EAL.WFInstanceID is null

SELECT Row_Number()OVER(ORDER BY EAL.ActivityLogID ) as RNUM, EAL.SRType, EAL.ActivityLogID, Case When EAL.ActivityCode IS NULL THEN TIA.PlainText ELSE TD.Name END As ActivityName, EAL.ActorID, TM.Name As ActorName, EAL.TeamID, TTT.Name As TeamName,TTT2.Name As CompanyName, EAL.ProcRoleTP, TD2.Name As ProcRoleTypeName, Case When LEN(EAL.Comment) > 50 Then LEFT(EAL.Comment, 50)+'...' Else EAL.Comment END As CommentFiltered, TD3.TypeCode As ActivityCode, TD3.Name As ActivityStatus, CONVERT(CHAR(19), EAL.StartTime, 120)As StartTime, CONVERT(CHAR(10), EAL.DueDate, 120)As DueDate, CONVERT(CHAR(19), EAL.EndTime, 120)As EndTime, STUFF((SELECT distinct ', ' + TM2.Name FROM XBOLTAPP.ESM_MBR_RCD ESM INNER JOIN XBOLTADM.TB_MEMBER TM2 ON TM2.MemberID = ESM.MemberID WHERE ESM.SpeCode = EAL.SpeCode AND ESM.SRID = EAL.PID FOR XML PATH('') ), 1, 1, '') AS ReferenceMembers, EAL.Status, EAL.Blocked, EAL.speCode, EAL.Seq ActivitySeq, EAL.WFInstanceID ActivityWFInstanceID, EAL.DocCategory FROM XBOLTAPP.ESM_ACTIVITY_LOG EAL WITH(NOLOCK) Left Outer Join XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) ON TD.TypeCode = EAL.ActivityCode And TD.Category = 'ACTP' And TD.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_MEMBER TM WITH(NOLOCK) ON TM.MemberID = EAL.ActorID Left Outer Join XBOLTADM.TB_TEAM_TXT TTT WITH(NOLOCK) ON TTT.TeamID = EAL.TeamID And TTT.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM TI WITH(NOLOCK) ON TI.Identifier = EAL.SpeCode AND TI.ClassCode = 'CL03004' Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TI.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD2 WITH(NOLOCK) ON TD2.TypeCode = EAL.ProcRoleTP And TD2.Category = 'SRROLETP' And TD2.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD3 WITH(NOLOCK) ON TD3.TypeCode = EAL.Status And TD3.Category = 'ACTVTYSTS' And TD3.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM TT WITH(NOLOCK) ON EAL.TeamID = TT.TeamID Left Outer Join XBOLTAPP.CRM_CUST_MST CCM WITH(NOLOCK) ON TT.ClientID = CCM.CustomerNo Left Outer Join XBOLTADM.TB_TEAM_TXT TTT2 WITH(NOLOCK) ON TTT2.TeamID = CCM.TeamID And TTT2.LanguageID = #{languageID} Where EAL.PID = #{srID}
AND EAL.SpeCode = #{speCode}
And EAL.Status NOT IN (${notInActivityStatusList})
And EAL.Status IN (${activityStatusList})
And EAL.Seq = ( SELECT MAX(Seq) FROM XBOLTAPP.ESM_ACTIVITY_LOG WITH(NOLOCK) WHERE SpeCode = #{speCode} AND PID = #{srID} )
And EAL.Seq = #{seq}
AND EAL.WFInstanceID = #{wfInstanceID}
AND EAL.ActivityLogID = #{activityLogID}
Order By EAL.ActivityLogID

SELECT T.RowNum, T.ActorID, T.ProcRoleTP, T.SortNum, T.WFInstanceID, T.Status FROM(
	SELECT
		ROW_NUMBER() OVER (ORDER BY ActivityLogID DESC) AS RowNum, ActorID, ProcRoleTP, SortNum, WFInstanceID, Status
	FROM XBOLTAPP.ESM_ACTIVITY_LOG EAL
	Where EAL.PID = #{srID} 	
	
    And EAL.Status NOT IN (${notInActivityStatusList})
    
) T
WHERE T.RowNum = #{SortNum}

Select TD.Name  From XBOLTAPP.ESM_ACTIVITY_LOG EAL
Left Outer Join XBOLTADM.TB_DICTIONARY TD ON TD.TypeCode = EAL.Status And TD.Category = 'ACTVTYSTS' And TD.LanguageID = #{languageID}
Where EAL.PID = #{srID} And EAL.SpeCode = #{speCode}

	And EAL.Seq = (
				    SELECT MAX(Seq)
				    FROM XBOLTAPP.ESM_ACTIVITY_LOG
				    WHERE SpeCode = #{speCode}
				    AND PID = #{srID}
				  )

Select Distinct ESCA.SpeCode, TIA.PlainText AS Name, ESCA.SortNum
From XBOLTAPP.ESM_SR_CAT_ATTR ESCA		
Left Outer Join XBOLTADM.TB_ITEM TI ON TI.Identifier = ESCA.SpeCode 
Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = TI.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID}
Where ESCA.SRCatID = #{srCatID}
  Order by ESCA.SortNum

Select TIA.LovCode 
From XBOLTADM.TB_ITEM_ATTR TIA, XBOLTADM.Tb_ITEM TI
Where TIA.ItemID = TI.ItemID 
And TIA.AttrTypeCode = #{attrTypeCode}
And TI.Identifier = #{identifier}

		Select 
			   TSC.SRCatID AS CODE, TD.Name AS NAME 
		From XBOLTAPP.ESM_SR_CAT_CFG TSC
		Left Outer Join XBOLTAPP.ESM_SR_CAT ESC ON ESC.SRCatID = TSC.SRCatID
		Left Outer Join XBOLTADM.TB_DICTIONARY TD ON TD.TypeCode  = TSC.SRCatID And TD.Category = 'SRCAT' And TD.LanguageID = #{languageID}
		Where TSC.SRType = #{srType}
			AND TSC.ClientID = #{customerNo}
		
			AND ESC.Level = #{level}
		
 		
			AND ESC.ParentID = #{parentID} 
		
		
			AND TSC.itemTypeCode IN (#{itemTypeCode},'')

Select T.SortNum, T.AttrTypeCode, T.Name, T.PlainText,T.LovCode , T.DataType, T.Domain, T.IsComLang, T.HTML, T.Mandatory, T.Editable, T.AreaHeight , T.RowNum, T.ColumnNum, T.SubAttrTypeCode
, T.AttrTypeCode2, T.Name2, T.PlainText2 , T.LovCode2, T.DataType2, T.Domain2, T.IsComLang2, T.HTML2 , T.Mandatory2, T.Editable2, T.AreaHeight2 , T.RowNum2, T.ColumnNum2, T.SubAttrTypeCode2 From (
Select EAAT.SortNum, EAAT.AttrTypeCode, TD.Name , Case TAT.DataType When 'MLOV' Then '' When 'MBR' Then '' Else ESA.Value End AS PlainText , Case TAT.DataType When 'MLOV' Then '' When 'MBR' Then '' ELSE ESA.LovCode End AS LovCode , TAT.DataType, TAT.Domain, TAT.IsComLang, TAT.HTML, EAAT.Mandatory, EAAT.Editable , ISNULL(EAAT.AreaHeight, 20) AS AreaHeight , EAAT.RowNum, EAAT.ColumnNum, TAT.SubAttrTypeCode
, EAAT2.AttrTypeCode AS AttrTypeCode2, TD2.Name AS Name2 , Case TAT2.DataType When 'MLOV' Then '' When 'MBR' Then '' Else ESA2.Value End AS PlainText2 , Case TAT2.DataType When 'MLOV' Then '' When 'MBR' Then '' ELSE ESA2.LovCode End AS LovCode2 , TAT2.DataType AS DataType2, TAT2.Domain AS Domain2, TAT2.IsComLang AS IsComLang2, TAT2.HTML AS HTML2 , EAAT2.Mandatory AS Mandatory2, EAAT2.Editable AS Editable2 , ISNULL(EAAT2.AreaHeight,20) AS AreaHeight2 , EAAT2.RowNum AS RowNum2, EAAT2.ColumnNum AS ColumnNum2, TAT2.SubAttrTypeCode AS SubAttrTypeCode2
From XBOLTAPP.ESM_ACTIVITY_ATTR_TYPE EAAT WITH(NOLOCK) Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT WITH(NOLOCK) ON TAT.AttrTypeCode = EAAT.AttrTypeCode Left Outer Join XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) ON TD.TypeCode = TAT.AttrTypeCode And TD.LanguageID = #{languageID}
Left Outer Join XBOLTAPP.ESM_SCR_ATTR_REV ESA WITH(NOLOCK) ON ESA.SCRID = #{scrID} And ESA.AttrTypeCode = EAAT.AttrTypeCode And ESA.ActivitySeq = #{activitySeq}
Left Outer Join XBOLTAPP.ESM_WKS_ATTR_REV ESA WITH(NOLOCK) ON ESA.SRID = #{srID} And ESA.AttrTypeCode = EAAT.AttrTypeCode And ESA.ActivitySeq = #{activitySeq}
Left Outer Join XBOLTAPP.ESM_SR_ATTR_REV ESA WITH(NOLOCK) ON ESA.SRID = #{srID} And ESA.AttrTypeCode = EAAT.AttrTypeCode And ESA.ActivitySeq = #{activitySeq}
Left Outer Join XBOLTAPP.ESM_ACTIVITY_ATTR_TYPE EAAT2 WITH(NOLOCK) ON EAAT2.SpeCode = #{speCode} And EAAT2.RowNum = EAAT.RowNum And EAAT2.ColumnNum = 2 And EAAT2.SRType = #{srType}
And ISNULL(EAAT2.Invisible,'') != '1'
Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT2 WITH(NOLOCK) ON TAT2.AttrTypeCode = EAAT2.AttrTypeCode Left Outer Join XBOLTADM.TB_DICTIONARY TD2 WITH(NOLOCK) ON TD2.TypeCode = TAT2.AttrTypeCode And TD2.LanguageID = #{languageID}
Left Outer Join XBOLTAPP.ESM_SCR_ATTR_REV ESA2 WITH(NOLOCK) ON ESA2.SCRID = #{scrID} And ESA2.AttrTypeCode = EAAT2.AttrTypeCode And ESA2.ActivitySeq = #{activitySeq}
Left Outer Join XBOLTAPP.ESM_WKS_ATTR_REV ESA2 WITH(NOLOCK) ON ESA2.SRID = #{srID} And ESA2.AttrTypeCode = EAAT2.AttrTypeCode And ESA2.ActivitySeq = #{activitySeq}
Left Outer Join XBOLTAPP.ESM_SR_ATTR_REV ESA2 WITH(NOLOCK) ON ESA2.SRID = #{srID} And ESA2.AttrTypeCode = EAAT2.AttrTypeCode And ESA2.ActivitySeq = #{activitySeq}
Where EAAT.SpeCode = #{speCode} And EAAT.DocCategory = #{docCategory} AND ISNULL(EAAT.ColumnNum,'') != 2 And EAAT.SRType = #{srType}
And ISNULL(EAAT.Invisible,'') != '1'
) T Group By T.SortNum, T.AttrTypeCode, T.Name, T.PlainText,T.LovCode, T.DataType, T.Domain, T.IsComLang, T.HTML, T.Mandatory, T.Editable, T.AreaHeight , T.RowNum, T.ColumnNum, T.SubAttrTypeCode , T.AttrTypeCode2, T.Name2 , T.PlainText2 , T.LovCode2, T.DataType2, T.Domain2, T.IsComLang2, T.HTML2 , T.Mandatory2, T.Editable2, T.AreaHeight2 , T.RowNum2, T.ColumnNum2, T.SubAttrTypeCode2 Order by T.SortNum ASC

SELECT distinct EAAT.SortNum ,EAAT.AttrTypeCode AS AttrTypeCode , ISNULL(TD.Name, '') AS Name , CASE TAT.DataType WHEN 'LOV' THEN TATL.Value WHEN 'MLOV' THEN '' WHEN 'Text' THEN ISNULL(ESA.Value,'') WHEN 'MBR' THEN '' ELSE ISNULL(ESA.Value, '') END PlainText , TAT.Style , EAAT.DefaultValue , CASE TAT.DataType WHEN 'MLOV' Then '' WHEN 'MBR' Then '' ELSE ISNULL(ESA.LovCode, '') END AS LovCode , ISNULL(EAAT.AttrTypeCode, '') AS BaseLovCode , TAT.DataType , TAT.IsComLang , TAT.HTML , ISNULL(EAAT.Mandatory, '') AS Mandatory , ISNULL(EAAT.Editable, '') AS Editable
, ISNULL(EAAT.AreaHeight, '20') AS AreaHeight , TAT.Editable as editYN , EAAT.RowNum , EAAT.ColumnNum , TAT.SubAttrTypeCode , EAAT.VarFilter , EAAT.CtrlType FROM XBOLTAPP.ESM_ACTIVITY_ATTR_TYPE EAAT WITH(NOLOCK)
Left Outer Join XBOLTAPP.ESM_SCR_ATTR ESA WITH(NOLOCK) ON ESA.AttrTypeCode = EAAT.AttrTypeCode AND ESA.SCRID = #{scrID}
Left Outer Join XBOLTAPP.ESM_WKS_ATTR ESA WITH(NOLOCK) ON ESA.AttrTypeCode = EAAT.AttrTypeCode AND ESA.SRID = #{srID}
Left Outer Join XBOLTAPP.ESM_SR_ATTR ESA WITH(NOLOCK) ON ESA.AttrTypeCode = EAAT.AttrTypeCode AND ESA.SRID = #{srID}
Left Outer Join XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) ON EAAT.AttrTypeCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left Outer join XBOLTADM.TB_ATTR_TYPE_LOV TATL WITH(NOLOCK) ON TATL.AttrTypeCode = ESA.AttrTypeCode AND TATL.LovCode = ESA.LovCode AND TATL.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT WITH(NOLOCK) ON EAAT.AttrTypeCode = TAT.AttrTypeCode WHERE EAAT.DocCategory = #{docCategory} And EAAT.SpeCode = #{speCode} And EAAT.SRType = #{srType}
And ISNULL(EAAT.Invisible,'') != '1'
ORDER BY EAAT.SortNum ASC

SELECT distinct EAAT.SortNum ,EAAT.AttrTypeCode AS AttrTypeCode , ISNULL(TD.Name, '') AS Name , CASE TAT.DataType WHEN 'LOV' THEN TATL.Value WHEN 'MLOV' THEN '' WHEN 'Text' THEN ISNULL(ESA.Value,'') WHEN 'MBR' THEN '' ELSE ISNULL(ESA.Value, '') END PlainText , CASE TAT.DataType WHEN 'MLOV' Then '' WHEN 'MBR' Then '' ELSE ISNULL(ESA.LovCode, '') END AS LovCode , ISNULL(EAAT.AttrTypeCode, '') AS BaseLovCode , TAT.DataType , TAT.IsComLang , TAT.HTML , ISNULL(EAAT.Mandatory, '') AS Mandatory , ISNULL(EAAT.Editable, '') AS Editable
, ISNULL(EAAT.AreaHeight, '20') AS AreaHeight , TAT.Editable as editYN , EAAT.RowNum , EAAT.ColumnNum , TAT.SubAttrTypeCode FROM XBOLTAPP.ESM_ACTIVITY_ATTR_TYPE EAAT WITH(NOLOCK)
Left Outer Join XBOLTAPP.ESM_SCR_ATTR_REV ESA WITH(NOLOCK) ON ESA.AttrTypeCode = EAAT.AttrTypeCode AND ESA.SCRID = #{scrID} AND ESA.ActivitySeq = #{activitySeq}
Left Outer Join XBOLTAPP.ESM_WKS_ATTR_REV ESA WITH(NOLOCK) ON ESA.AttrTypeCode = EAAT.AttrTypeCode AND ESA.SRID = #{srID} AND ESA.ActivitySeq = #{activitySeq}
Left Outer Join XBOLTAPP.ESM_SR_ATTR_REV ESA WITH(NOLOCK) ON ESA.AttrTypeCode = EAAT.AttrTypeCode AND ESA.SRID = #{srID} AND ESA.ActivitySeq = #{activitySeq}
Left Outer Join XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) ON EAAT.AttrTypeCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left Outer join XBOLTADM.TB_ATTR_TYPE_LOV TATL WITH(NOLOCK) ON TATL.AttrTypeCode = ESA.AttrTypeCode AND TATL.LovCode = ESA.LovCode AND TATL.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ATTR_TYPE TAT WITH(NOLOCK) ON EAAT.AttrTypeCode = TAT.AttrTypeCode WHERE EAAT.DocCategory = #{docCategory} And EAAT.SpeCode = #{speCode} And EAAT.SRType = #{srType}
And ISNULL(EAAT.Invisible,'') != '1'
ORDER BY EAAT.SortNum ASC

Select ESA.LovCode AS Code
 , TM.Name AS Name 
From

	
	XBOLTAPP.ESM_SCR_ATTR ESA
	
	
	XBOLTAPP.ESM_WKS_ATTR ESA
	
	
