	,SRType = #{SRType}
	,ActorID = #{ActorID}
	,TeamID = #{TeamID}
	,SpeCode = #{SpeCode}
	,ActivityCode = #{ActivityCode}
	,ProcRoleTP = #{procRoleTP}
	,DocCategory = #{DocCategory}
	,DocumentID = #{DocumentID}
	,Status = #{Status}
	,StartTime = #{StartTime}
	,DueDate = #{DueDate}
	,EndTime = #{EndTime}
	,Comment = #{Comment}
	,TeamNM = #{TeamNM}
	,SortNum = #{SortNum}
	,Blocked = #{Blocked}
	,WFInstanceID = #{WFInstanceID}
	,PrevSRCategory = #{PrevSRCategory}
	,PrevSRType = #{PrevSRType}
	
Where 
PID = #{PID}
