Select Row_Number()OVER(ORDER BY TF.Seq, TF.FltpCode) AS RNUM , TF.Seq , TF.FltpCode , TF.FileRealName AS FileRealName , TF.FileName AS FileRealName , TD.Name AS FltpName From XBOLTADM.TB_FILE TF Left Outer Join XBOLTAPP.ESM_FLTP_ALLOC EFA ON EFA.FltpCode = TF.FltpCode Left Outer Join XBOLTADM.TB_DICTIONARY TD On TD.TypeCode = TF.FltpCode AND TD.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TF.LastUser Where EFA.DocCategory = #{docCategory} And EFA.SpeCode= #{speCode}
And TF.Seq IN (Select TemplFileID From XBOLTAPP.ESM_FLTP_ALLOC Where SRTypeCode = #{srType} And DocCategory = #{docCategory} And SpeCode = #{speCode})
And TF.DocumentID = #{documentID}

SELECT  SCRID
FROM xboltapp.ESM_SCR_MST
WHERE SRID = #{srID}

SELECT ProcRoleTP,Status AS SpeCode
FROM XBOLTAPP.ESM_SR_MST
WHERE SRID = #{srID}

Select EAAT.AttrTypeCode AS CODE, TD.Name AS NAME
From XBOLTAPP.ESM_ACTIVITY_ATTR_TYPE EAAT
Left Outer Join XBOLTADM.TB_DICTIONARY TD ON TD.TypeCode = EAAT.AttrTypeCode And TD.LanguageID = #{languageID}
  Where EAAT.SRType = #{srType}
  And EAAT.SpeCode = #{speCode}

Select Top ${top} Row_Number()OVER(ORDER BY TBD.RegDTOrg DESC ) as RNUM, TBD.* From( Select TSM.SRID, TSM.SRCode, TSM.SRType, TSM.ESType, TSM.SRTypeNM, TSM.ProcRoleTP, TSM.Blocked, TSM.CompanyName, TSM.ClientID,TSM.ProjectID, TSM.Subject, TSM.SRArea1, TSM.SRArea1Name, TSM.SRArea2, TSM.SRArea2Name, TSM.Category, TSM.CategoryNM, TSM.SubCategory, TSM.SubCategoryNM, TSM.Status, TSM.StatusName, TSM.RegUserID, TSM.RegUserName, TSM.RegTeamID, TSM.RegTeamName, ISNULL(CONVERT(char(10),TSM.RegDT, 120),'') as RegDate, TSM.RequestUserID, TSM.ReqUserNM, TSM.RequestTeamID, TSM.ReqTeamNM, ISNULL(CONVERT(char(10),TSM.DueDate, 120),'') as SRDueDate, ISNULL(CONVERT(char(10),TSM.ReqDueDate, 120),'') as ReqDueDate, TSM.ReceiptUserID, TSM.ReceiptName, TSM.ReceiptTeamID, TSM.ReceiptTeamName, TSM.ReceiptName + '(' + TSM.ReceiptTeamName + ')' as ReceiptInfo, TSM.ReqUserNM + '(' + TSM.ReqTeamNM + ')' as RequestInfo, TSM.ResponseUserID, TSM.ResponseUserName, TSM.ResponseTeamID, TSM.ResponseTeamName, TSM.ResponseUserName + '(' + TSM.ResponseTeamName + ')' as ResponseInfo, ISNULL(CONVERT(char(10),TSM.CompletionDT, 120),'') as SRCompletionDT,
TSM.RegDT As RegDTOrg, TSM.ReqDueDate AS ReqDueDateOrg, TSM.DueDate as DueDateOrg, TSM.CompletionDT As CompletionDTOrg, TSM.CompanyID, TSM.ReceiptTeamID As SRReceiptTeamID, Case When CompletionDT IS NULL Then 'N' Else 'Y' End AS SvcCompl, CONVERT(INT, DATEDIFF(DAY, TSM.Duedate, GETDATE())) as 'delayDay', ReceiptDelay = CASE WHEN TSM.Duedate is null THEN CASE WHEN CONVERT(INT, DATEDIFF(HH, TSM.RegDT, GETDATE())) >= 12 THEN 'Y' ELSE 'N' END ELSE 'N' END, CompletionDelay = CASE WHEN TSM.CompletionDT is null THEN CASE WHEN TSM.Duedate < GETDATE() THEN 'Y' ELSE 'N' END WHEN TSM.CompletionDT is not null THEN CASE WHEN TSM.Duedate < tsm.CompletionDT THEN 'Y' ELSE 'N' END END, TSM.ItemTypeCode, TSM.ProcRoleTypeName, TSM.ProcRoleTypeMemberList, TSM.isPublic, TSM.AT00035, TSM.APPINFRA
From XBOLTAPP.ESM_SR_MST TSM WITH(NOLOCK)
AND TSM.ESType = #{esType}
AND TSM.SRType = #{srType}
AND #{sessionUserID} In (TSM.RequestUserID, TSM.ReceiptUserID , TSM.RegUserID)
AND #{sessionUserID} In ( TSM.ReceiptUserID )
AND #{sessionUserID} In ( TSM.ReceiptUserID, TSM.ResponseUserID )
AND #{sessionUserID} In (TSM.RequestUserID)
AND #{sessionUserID} In (TSM.RequestUserID, TSM.ReceiptUserID)
AND TSM.ClientID = (Select ClientID from XBOLTADM.TB_MEMBER Where MemberID = #{sessionUserID} )
AND TSM.SRID In (Select PID from XBOLTADM.TB_PROC_LOG where ActorID = #{sessionUserID} and ActivityID = 'ACTP003')
AND #{myTeamId} In (TSM.RequestTeamID, TSM.ReceiptTeamID)
AND #{sessionUserID} In (SELECT MemberID FROM XBOLTADM.TB_MY_ITEM WHERE ItemID = TSM.SRArea2 AND Assigned = '1')
AND TSM.Status = #{srStatus}
AND TSM.Status IN (${srStatusArr})
AND TSM.ProjectID IN (Select ProjectID From XBOLTADM.TB_PROJECT Where RefPGID = #{refID} And ProjectType = 'PJT' )
AND TSM.ProjectID = #{refID}
AND TSM.ProjectID IN (Select ProjectID From XBOLTADM.TB_PJT_MEMBER_REL Where MemberID = #{sessionUserID} AND Involved = '1' )
AND TM3.Name like N'%'+#{requestUserName}+'%'
AND TM2.Name like N'%'+#{regUserName}+'%'
AND TM4.Name like N'%'+#{receiptUserName}+'%'
AND TSM.RegDT BETWEEN CAST(#{regStartDate} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{regEndDate} AS DATETIME)))
AND TSM.SRArea1 = #{srArea1}
AND TSM.SRArea2 = #{srArea2}
AND TSM.Category = #{category}
AND TSM.SubCategory = #{subCategory}
AND TSM.Priority = #{priority}
AND TSM.DueDate BETWEEN CAST(#{stSRDueDate} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{endSRDueDate} AS DATETIME)))
AND TSM.CompletionDT BETWEEN CAST(#{stSRCompDT} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{endSRCompDT} AS DATETIME)))
AND TSM.SRCode like N'%'+#{srCode}+'%'
AND TSM.SrID = #{srID}
AND TSM.RequestTeamID = #{requestTeam}
AND TSM.ResponseTeamID = #{responseTeamID}
AND TSM.ReceiptTeamID = #{srReceiptTeam}
AND TSM.Subject like N'%'+#{subject}+'%'
AND #{itemID} IN (TSM.SRArea1, TSM.SRArea2, TSM.SRArea3)
AND TSM.RequestTeamID IN (${requestTeamList})
AND ( TSM.CompanyID IN (${companyList}) OR TSM.RequestTeamID IN (${companyList}) )
AND TSM.ClientID = #{clientID}
AND TSM.CompanyID IN (#{companyID})
AND TSM.isPublic = #{isPublic}
AND TSM.SRID in (Select ToSRID From XBOLTAPP.ESM_SR_CXN Where FromSRID = #{fromSRID})
AND (1=1
${item.selectOption} TSM.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} And ISNULL(Value,'') NOT Like replace('%'+#{item.searchValue}+'%', ' ','') )
${item.selectOption} TSM.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} And LovCode NOT IN (
#{item2}
) )
${item.selectOption} TSM.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} )
${item.selectOption} TSM.SRID NOT IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR Where AttrTypeCode = #{item.attrCode} )
)
And ( TSM.SRID IN (Select SRID From XBOLTAPP.ESM_MBR_RCD Where SRID = TSM.SRID And MemberID = #{sessionUserID} AND SpeCode = TSM.Status ) OR ( #{sessionUserID} In ( TSM.ReceiptUserID ) AND TSM.Blocked = 0 AND TSM.ProcRoleTP != 'CLIENT' AND TSM.ProcRoleTP IS NOT NULL ) )
And TSM.ProcRoleTP IN (Select RoleType From XBOLTADM.TB_MY_ITEM Where (ItemID = TSM.SRArea2 OR ItemID = TSM.SRArea1) AND Assigned = '1' And MemberID IN (${procRoleTPGroupMemberIDs}))
And TSM.SRID IN ( Select PID From XBOLTAPP.ESM_ACTIVITY_LOG Where ActorID = #{sessionUserID} )
And TSM.ProjectID in ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{sessionUserID} And TP.ProjectType = 'CSR' )
AND TSM.RequestUserID = #{requestUserID}
And (TSM.SRID in ( SELECT distinct srid FROM XBOLTAPP.ESM_MBR_RCD Where MemberID = #{actorID}) or TSM.SRID IN (SELECT distinct DocumentID from XBOLTAPP.esm_activity_log where actorid = #{actorID}))
) AS TBD
And SvcCompl = 'N'
And SvcCompl = 'Y'
And TBD.IsPublic = 0
AND TBD.ReceiptDelay = #{receiptDelay}
AND TBD.CompletionDelay = #{completionDelay}
AND TBD.ItemCode like N'%'+#{itemCode}+'%'
AND TBD.ItemName like N'%'+#{itemName}+'%'
AND TBD.ItemTypeCode = #{itemTypeCode}
AND TBD.AT00035 = #{svcType}
Order By TBD.RegDTOrg DESC
OFFSET (${pageNo} - 1) * ${pageRow} ROWS FETCH NEXT ${pageRow} ROWS ONLY

 	Select 
		Row_Number()OVER(ORDER BY TBD.RegDTOrg DESC ) as RNUM, TBD.*
	From(
	 	Select
	 	 	TSM.SRID, TSM.SRCode, TSM.SRType, TSM.ESType, TD5.Name AS SRTypeNM, TSM.ProcRoleTP, TSM.Blocked,
			TEAM6.Name AS CompanyName, TSM.ClientID,TSM.ProjectID,
			TSM.Subject, TSM.SRArea1, TIA.PlainText As SRArea1Name,
			TSM.SRArea2, TIA2.PlainText As SRArea2Name,
			TSM.Category,  TD4.Name As CategoryNM,
			TSM.SubCategory, ISNULL(TD3.Name, TD4.Name) As SubCategoryNM,
			TSM.Status, TISA.PlainText As StatusName, TSM.RegUserID, TM2.Name As RegUserName,
			TSM.RegTeamID, TEAM1.Name As RegTeamName,
			ISNULL(CONVERT(char(10),TSM.RegDT, 120),'') as RegDate,				
			TSM.RequestUserID, TM3.Name As ReqUserNM,
			TSM.RequestTeamID, TEAM2.Name As ReqTeamNM,
			ISNULL(CONVERT(char(10),TSM.DueDate, 120),'') as SRDueDate,				
			ISNULL(CONVERT(char(10),TSM.ReqDueDate, 120),'') as ReqDueDate,				
			TSM.ReceiptUserID, TM4.Name As ReceiptName, 
			TSM.ReceiptTeamID, TEAM3.Name As ReceiptTeamName,
			TM4.Name + '(' + TEAM3.Name + ')' as ReceiptInfo,
			TM3.Name + '(' + TEAM2.Name + ')' as RequestInfo,
			TSM.ResponseUserID, TM5.Name As ResponseUserName,
			TSM.ResponseTeamID, TEAM4.Name As ResponseTeamName,
			TM5.Name + '(' + TEAM4.Name + ')' as ResponseInfo,
			ISNULL(CONVERT(char(10),TSM.CompletionDT, 120),'') as SRCompletionDT,
			
			TSM.RegDT As RegDTOrg,
			TSM.ReqDueDate AS ReqDueDateOrg,
			TSM.DueDate as DueDateOrg,
			TSM.CompletionDT As CompletionDTOrg,
			TSM.CompanyID,
			TSM.ReceiptTeamID As SRReceiptTeamID,
			Case When CompletionDT IS NULL Then 'N' Else 'Y' End AS SvcCompl,
			
			ReceiptDelay = CASE WHEN TSM.Duedate is null THEN 
											CASE WHEN CONVERT(INT, DATEDIFF(HH, TSM.RegDT, GETDATE())) >= 12 THEN 'Y'
													ELSE 'N'
											END
										ELSE 'N'
									END,
		 	CompletionDelay = CASE WHEN TSM.CompletionDT is null THEN 
													CASE 
														 WHEN TSM.Duedate < GETDATE() THEN 'Y' 
														ELSE 'N'
													END
													WHEN TSM.CompletionDT is not null THEN 
														CASE 
															WHEN TSM.Duedate < tsm.CompletionDT THEN 'Y'
															ELSE 'N'
														END
													END,
			TSM.ItemTypeCode,
			TD8.Name AS ProcRoleTypeName,
			XBOLTAPP.fn_GetESPRoleTPMemberList(TSM.ProcRoleTP, 
				 CASE WHEN (TSM.SRArea2 IS NULL OR TSM.SRArea2 = '' OR TSM.SRArea2 = '0') THEN TSM.SRArea1 ELSE TSM.SRArea2 END
			)  AS ProcRoleTypeMemberList,
			TSM.isPublic,
			
			TATL.Value AS SRAT0002,
			TM6.Name ReceiptInfoCallCenter,
		
			CASE WHEN ISNULL(TSM.SRArea1,'') = '' THEN ISNULL(SRArea1ATR.PlainText, '') ELSE ISNULL(SRArea2ATR.PlainText, '') END AS 'AT00035', 
			CASE WHEN ISNULL(TSM.SRArea2,'') = '' THEN ISNULL(TATL1.Value, '') ELSE ISNULL(TATL2.Value, '') END AS 'APP/INFRA' 
		
		From XBOLTAPP.ESM_SR_MST TSM WITH(NOLOCK)
		Left Outer Join XBOLTADM.TB_MEMBER TM2 WITH(NOLOCK) On TM2.MemberID = TSM.RegUserID
		Left Outer Join XBOLTADM.TB_MEMBER TM3 WITH(NOLOCK) On TM3.MemberID = TSM.RequestUserID
		Left Outer Join XBOLTADM.TB_MEMBER TM4 WITH(NOLOCK) On TM4.MemberID = TSM.ReceiptUserID
		Left Outer Join XBOLTADM.TB_MEMBER TM5 WITH(NOLOCK) On TM5.MemberID = TSM.ResponseUserID
		Left Outer Join XBOLTADM.TB_DICTIONARY TD4 WITH(NOLOCK) On TD4.TypeCode = TSM.Category AND TD4.Category = 'SRCAT' And TD4.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD3 WITH(NOLOCK) On TD3.TypeCode = TSM.SubCategory And TD3.Category = 'SRCAT' And TD3.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM TIS WITH(NOLOCK) ON TSM.Status = TIS.Identifier
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TISA WITH(NOLOCK) ON TISA.ItemID = TIS.ItemID And TISA.AttrTypeCode = 'AT00001' And TISA.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM1 WITH(NOLOCK) ON TEAM1.TeamID = TSM.RegTeamID And TEAM1.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM2 WITH(NOLOCK) ON TEAM2.TeamID = TSM.RequestTeamID And TEAM2.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM3 WITH(NOLOCK) ON TEAM3.TeamID = TSM.ReceiptTeamID And TEAM3.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM4 WITH(NOLOCK) ON TEAM4.TeamID = TSM.ResponseTeamID And TEAM4.LanguageID = #{languageID} 
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TSM.SRArea1 And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID  =  #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = TSM.SRArea2 And TIA2.AttrTypeCode = 'AT00001' And TIA2.LanguageID  =  #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD5 WITH(NOLOCK) On TD5.TypeCode = TSM.SRType And TD5.Category = 'SRTP' And TD5.LanguageID = #{languageID}
		Left Outer Join XBOLTAPP.CRM_CUST_MST CCM WITH(NOLOCK) ON TSM.ClientID = CCM.CustomerNo
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM6 WITH(NOLOCK) ON TEAM6.TeamID = CCM.TeamID And TEAM6.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD8 WITH(NOLOCK) On TD8.TypeCode = TSM.ProcRoleTP And TD8.Category = 'SRROLETP' And TD8.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM_ATTR SRArea1ATR WITH(NOLOCK) ON SRArea1ATR.ItemID = TSM.SRArea1 AND SRArea1ATR.AttrTypeCode = 'AT00035' AND SRArea1ATR.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ATTR_TYPE_LOV TATL1 WITH(NOLOCK) ON TATL1.AttrTypeCode = 'AT00035' AND TATL1.LovCode = SRArea1ATR.PlainText AND TATL1.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM_ATTR SRArea２ATR WITH(NOLOCK) ON SRArea２ATR.ItemID = TSM.SRArea1 AND SRArea２ATR.AttrTypeCode = 'AT00035' AND SRArea２ATR.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ATTR_TYPE_LOV TATL2 WITH(NOLOCK) ON TATL2.AttrTypeCode = 'AT00035' AND TATL2.LovCode = SRArea２ATR.PlainText AND TATL2.LanguageID = #{languageID}			
		
		
		Left Outer Join XBOLTAPP.ESM_SR_ATTR ESA WITH(NOLOCK) ON ESA.SRID = TSM.SRID And ESA.AttrTypeCode = 'SRAT0002'
		Left Outer Join XBOLTADM.TB_ATTR_TYPE_LOV TATL WITH(NOLOCK) ON TATL.AttrTypeCode = ESA.AttrTypeCode And TATL.LovCode = ESA.Value And TATL.LanguageID = #{languageID}
		left outer join XBOLTAPP.ESM_ACTIVITY_LOG EAL1 WITH(NOLOCK) ON EAL1.PID = TSM.SRID AND EAL1.SpeCode = 'REQ0002' AND EAL1.Seq = ( SELECT MAX(Seq) FROM XBOLTAPP.ESM_ACTIVITY_LOG WHERE SpeCode = 'REQ0002' AND PID = TSM.SRID)
		Left Outer Join XBOLTADM.TB_MEMBER TM6 WITH(NOLOCK) On TM6.MemberID = EAL1.ActorID
		 
		
		
	    
			AND TSM.ESType = #{esType}
		
		
			AND TSM.SRType = #{srType}
		
		
			AND #{sessionUserID} In (TSM.RequestUserID, TSM.ReceiptUserID , TSM.RegUserID)
		
		
			AND #{sessionUserID} In ( TSM.ReceiptUserID )
		
		
			AND #{sessionUserID} In ( TSM.ReceiptUserID, TSM.ResponseUserID )
		
		
			AND #{sessionUserID} In (TSM.RequestUserID)
		
		
			AND #{sessionUserID}  In (TSM.RequestUserID, TSM.ReceiptUserID)
		
		
			AND TSM.ClientID = (Select ClientID from XBOLTADM.TB_MEMBER Where MemberID = #{sessionUserID} )
		
		
			AND TSM.SRID In (Select PID from XBOLTADM.TB_PROC_LOG where ActorID = #{sessionUserID} and ActivityID = 'ACTP003')
		
		
			AND #{myTeamId}  In (TSM.RequestTeamID, TSM.ReceiptTeamID)
		
		
			AND #{sessionUserID} In (SELECT MemberID FROM XBOLTADM.TB_MY_ITEM WHERE ItemID = TSM.SRArea2 AND Assigned = '1')
				
		
			AND TSM.Status = #{srStatus}
		
		
			AND TSM.Status IN (${srStatusArr})
		
		
			AND TSM.ProjectID IN (Select ProjectID From XBOLTADM.TB_PROJECT Where RefPGID = #{refID} And ProjectType = 'PJT' )
			
		
			AND TSM.ProjectID = #{refID} 
			
		
			AND TSM.ProjectID IN (Select ProjectID From XBOLTADM.TB_PJT_MEMBER_REL Where MemberID = #{sessionUserID} AND Involved = '1' )
			
		
			AND TM3.Name like N'%'+#{requestUserName}+'%'
		
		
			AND TM2.Name like N'%'+#{regUserName}+'%'
		
		
			AND TM4.Name like N'%'+#{receiptUserName}+'%'
		
		
			AND TSM.RegDT BETWEEN CAST(#{regStartDate} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{regEndDate} AS DATETIME)))
		
		
			AND TSM.SRArea1 = #{srArea1}
		
		
			AND TSM.SRArea2 = #{srArea2}
		
		
			AND TSM.Category = #{category} 
		
		
			AND TSM.SubCategory = #{subCategory}
		
		
			AND TSM.Priority = #{priority} 
		
		
			AND TSM.DueDate BETWEEN CAST(#{stSRDueDate} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{endSRDueDate} AS DATETIME)))
		
		
			AND TSM.CompletionDT BETWEEN CAST(#{stSRCompDT} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{endSRCompDT} AS DATETIME)))
		
		
			AND TSM.SRCode like N'%'+#{srCode}+'%'
		
		
			AND TSM.SrID = #{srID}
		
		
			AND TSM.RequestTeamID = #{requestTeam}
		
		
			AND TSM.ResponseTeamID = #{responseTeamID}
		
		
			AND TSM.ReceiptTeamID = #{srReceiptTeam}
		
		
			AND TSM.Subject like N'%'+#{subject}+'%'
		
		
			AND #{itemID}  IN (TSM.SRArea1, TSM.SRArea2, TSM.SRArea3)
		
		
			AND TSM.RequestTeamID IN (${requestTeamList})
		
		
			AND ( TSM.CompanyID IN (${companyList}) OR TSM.RequestTeamID IN (${companyList}) )
		
		
			AND TSM.ClientID = #{clientID}
		
		
			AND TSM.CompanyID IN (#{companyID})
		
		
			AND TSM.isPublic = #{isPublic}
		
		
			AND TSM.SRID in (Select ToSRID From XBOLTAPP.ESM_SR_CXN Where FromSRID = #{fromSRID})
		
		
		 
			AND (1=1
			
				
					
					${item.selectOption} TSM.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR 
									Where AttrTypeCode = #{item.attrCode}
									And ISNULL(Value,'')
									NOT
									Like replace('%'+#{item.searchValue}+'%', ' ','')
								)
					
					
					
						${item.selectOption} TSM.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR 
							Where AttrTypeCode = #{item.attrCode}
							And LovCode 
							NOT
							IN (
							
								#{item2}
							
							)
						)
						
					
								
					
						
							
							${item.selectOption} TSM.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR 
										Where AttrTypeCode = #{item.attrCode}
									)
							
							
							${item.selectOption} TSM.SRID NOT IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR 
										Where AttrTypeCode = #{item.attrCode}
									)
							
						
					
				
			
			)
		
		
			And (
				TSM.SRID IN (Select SRID From XBOLTAPP.ESM_MBR_RCD Where SRID = TSM.SRID And MemberID = #{sessionUserID} AND SpeCode = TSM.Status ) 
				OR ( #{sessionUserID} In ( TSM.ReceiptUserID ) AND TSM.Blocked = 0 AND TSM.ProcRoleTP != 'CLIENT' AND TSM.ProcRoleTP IS NOT NULL )
			)
		
		
			And TSM.ProcRoleTP IN (Select RoleType From XBOLTADM.TB_MY_ITEM Where (ItemID = TSM.SRArea2 OR ItemID = TSM.SRArea1) AND Assigned = '1' And MemberID IN (${procRoleTPGroupMemberIDs}))
		
		
			And TSM.SRID IN ( Select PID From XBOLTAPP.ESM_ACTIVITY_LOG Where ActorID = #{sessionUserID} )
		
		
			And TSM.ProjectID in (
				SELECT TP.ProjectID
				FROM XBOLTADM.TB_PROJECT TP
				left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR on TP.ProjectID = TPMR.ProjectID
				Where TPMR.MemberID = #{sessionUserID}
				And TP.ProjectType = 'CSR'
			)
		
		
			AND TSM.RequestUserID = #{requestUserID}
		
		
		
			And (TSM.SRID in ( SELECT distinct srid FROM XBOLTAPP.ESM_MBR_RCD Where MemberID = #{actorID}) or TSM.SRID IN (SELECT distinct DocumentID from XBOLTAPP.esm_activity_log where actorid = #{actorID}))
		
	
	) AS TBD 
	
		
			
				
					And SvcCompl = 'N' 
				
				
					And SvcCompl = 'Y' 
				
				
				
				
					And TBD.IsPublic = 0
				
			
		
		
			AND TBD.ReceiptDelay = #{receiptDelay}
		
		
			AND TBD.CompletionDelay = #{completionDelay}
		
		
			AND TBD.ItemCode like N'%'+#{itemCode}+'%'
		
		
			AND TBD.ItemName like N'%'+#{itemName}+'%'
		
		
			AND TBD.ItemTypeCode = #{itemTypeCode}
		
		
			AND TBD.AT00035 = #{svcType}
		
	
	Order By  TBD.RegDTOrg DESC

 	Select Max(ISNULL(Seq,0)) as Seq
	From XBOLTAPP.ESM_ACTIVITY_LOG
	Where PID = #{srID} AND SpeCode = #{status}

 	Select CompletionDT
	From XBOLTAPP.ESM_SR_MST
	Where SRID = #{srID}

SELECT * FROM( SELECT itfl.Seq , Row_Number() OVER (order by itfl.Version ASC, itfl.LastUpdated ASC, itfl.FltpCode ASC, itfl.FileRealName ASC) AS RNUM ,0 as CHK ,mst.SRCode ,mst.Subject ,mst.SRType ,td2.Name SRTypeNM ,mst.SRArea1 ,mst.SRArea2 ,itfl.SpeCode ,ATR3.PlainText SpeCodeNM ,ISNULL(ATR.PlainText,'')+'/ '+ISNULL(ATR2.PlainText,'') AS SRService ,TD.Name AS FltpNM ,itfl.fltpcode ,itfl.DocumentID ,itfl.DocCategory ,itfl.LinkType ,itfl.FileName ,itfl.FileFormat ,itfl.FileRealName ,itfl.FileSize ,itfl.FileMgt ,itfl.RegMemberID ,itfl.RefFileID ,itfl.CreationTime ,itfl.LastUpdated , CASE WHEN ISNULL(TM.Name,'') != '' THEN ISNULL(TM.Name,'') + Case When ISNULL(TM.NameEN,'') != '' Then '(' + ISNULL(TM.NameEN,'') + ')' Else '' End ELSE ISNULL(mbr.Name,'') + Case When ISNULL(mbr.NameEN,'') != '' Then '(' + ISNULL(mbr.NameEN,'') + ')' Else '' End END AS WriteUserNM ,( select t2.name from XBOLTADM.TB_MEMBER t1 left outer join XBOLTADM.TB_TEAM_TXT t2 on t1.teamId = t2.teamId where t1.memberId = itfl.RegMemberID and t2.LanguageID = #{languageID} ) as TeamName ,CASE WHEN itfl.Blocked != 0 then 'Y' ELSE '-' END Blocked ,mst.ClientID ,TX.Name CompanyName ,mst.ProjectID ,fltp.FilePath as srFilePath ,TATL.Value as SRAT0004 FROM XBOLTADM.TB_FILE itfl WITH(NOLOCK) INNER JOIN XBOLTAPP.ESM_SR_MST mst WITH(NOLOCK) on itfl.DocumentID = mst.SRID INNER JOIN XBOLTADM.TB_MEMBER mbr WITH(NOLOCK) ON itfl.RegMemberID = mbr.MemberID INNER JOIN XBOLTADM.TB_FLTP fltp WITH(NOLOCK) ON itfl.FltpCode = fltp.FltpCode INNER JOIN XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) ON itfl.FltpCode = TD.TypeCode AND TD.languageID = #{languageID} AND TD.Category ='FLTP'
INNER Join XBOLTADM.TB_ITEM_ATTR ATR WITH(NOLOCK) ON ATR.ItemID = mst.SRArea1 and ATR.AttrTypeCode = 'AT00001' and ATR.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR ATR2 WITH(NOLOCK) ON ATR2.ItemID = mst.SRArea2 and ATR2.AttrTypeCode = 'AT00001' and ATR2.LanguageID = #{languageID}
INNER Join XBOLTADM.TB_TEAM T WITH(NOLOCK) ON mst.ClientID = T.ClientID AND T.TeamType = 2 INNER Join XBOLTADM.TB_TEAM_TXT TX WITH(NOLOCK) ON T.TeamID = TX.TeamID and TX.LanguageID = #{languageID} INNER JOIN XBOLTADM.TB_DICTIONARY TD2 WITH(NOLOCK) ON TD2.TypeCode = mst.SRType AND TD2.languageID = #{languageID} and TD2.Category = 'SRTP'
LEFT OUTER JOIN XBOLTADM.TB_ITEM ITM WITH(NOLOCK) on ITM.Identifier = itfl.SpeCode LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR ATR3 WITH(NOLOCK) on ATR3.ItemID = ITM.ItemID and ATR3.AttrTypeCode = 'AT00001' and ATR3.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTAPP.ESM_ACTIVITY_LOG EAL WITH(NOLOCK) ON EAL.PID = itfl.RefDocumentID And EAL.SpeCode = itfl.SpeCode LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM WITH(NOLOCK) ON TM.MemberID = EAL.ActorID LEFT OUTER JOIN XBOLTAPP.ESM_SR_ATTR ESA WITH(NOLOCK) ON ESA.SRID = itfl.DocumentID AND ESA.AttrTypeCode = 'SRAT0004' LEFT OUTER JOIN XBOLTADM.TB_ATTR_TYPE_LOV TATL WITH(NOLOCK) ON TATL.AttrTypeCode = 'SRAT0004' AND TATL.LanguageID = #{languageID} AND TATL.LovCode = ESA.LovCode
And itfl.DocumentID = #{srID}
And itfl.FltpCode = #{fltpCode}
And msT.SRCode LIKE CONCAT('%', #{SRCode}, '%')
And mst.RegDT BETWEEN CAST(#{reg_STR_DT} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{reg_END_DT} AS DATETIME)))
And mst.Subject LIKE CONCAT('%', #{searchValue}, '%')
And itfl.FileRealName LIKE CONCAT('%', #{fileNM}, '%')
And itfl.ProjectID = #{projectID}
And itfl.SpeCode = #{speCode}
And mst.ProjectID in ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{userID} And TP.ProjectType = 'CSR' )
And mbr.MemberID = #{userID}
And mst.SRType = #{searchSrType}
And mst.RequestUserID = #{requestUserID}
And mst.ReceiptUserID = #{receiptUserID}
And ESA.LovCode = #{SRAT0004}
And mst.SRArea1 = #{srArea1}
And mst.SRArea2 = #{srArea2}
) TC order by TC.RNUM DESC

Select SRID 
  From XBOLTAPP.ESM_SR_MST
Where SRCode = #{srCode}

Select Count(MemberID) as total
  From XBOLTAPP.ESM_SR_MST
Where SRCode = #{procRoleTP}

Select Count(*) as total
  From XBOLTAPP.ESM_SR_ATTR_REV
Where SRID = #{srID} AND ActivitySeq = #{activitySeq} AND speCode = #{speCode}

SELECT Row_Number() OVER(ORDER BY ITM2.ClientID, ITM1.Identifier, ITM2.Identifier ) AS RNUM ,ITM1.ClientID ,Domain.Plaintext As CompanyName ,SRArea1ITM.itemID As SRArea1 ,ITM1.Identifier Identifier1 ,SRArea1ATR.PlainText As SRArea1Name ,ITM2.ItemID AS SRArea2 , ITM2.Identifier Identifier2 ,ISNULL(SRArea2ATR.PlainText, '') AS SRArea2Name ,CASE WHEN ISNULL(ITM2.ItemID,'') = '' THEN ISNULL(SRArea1ATR2.PlainText, '') ELSE ISNULL(SRArea2ATR2.PlainText, '') END AS 'APP/INFRA Code' ,CASE WHEN ISNULL(ITM2.ItemID,'') = '' THEN ISNULL(TATL1.Value, '') ELSE ISNULL(TATL2.Value, '') END AS 'APP/INFRA' FROM
XBOLTADM.TB_ITEM_ATTR SRType WITH(NOLOCK), XBOLTADM.TB_ITEM_ATTR SRArea1ATR WITH(NOLOCK), XBOLTADM.TB_ITEM_ATTR SRArea1ITM WITH(NOLOCK) Inner Join XBOLTADM.TB_ITEM ITM1 WITH(NOLOCK)ON ITM1.ItemID = SRArea1ITM.ItemID Inner Join XBOLTAPP.CRM_CUST_MST CCM WITH(NOLOCK) ON ITM1.clientID = CCM.CustomerNo inner Join XBOLTADM.TB_ITEM_ATTR SRArea1ATR2 WITH(NOLOCK) ON SRArea1ATR2.ItemID = SRArea1ITM.ItemID AND SRArea1ATR2.AttrTypeCode = 'AT00035' AND SRArea1ATR2.LanguageID = ${languageID} inner join XBOLTADM.TB_ATTR_TYPE_LOV TATL1 WITH(NOLOCK) ON TATL1.AttrTypeCode = 'AT00035' AND TATL1.LovCode = SRArea1ATR2.PlainText AND TATL1.LanguageID = ${languageID}
left outer Join XBOLTADM.TB_ITEM ITM WITH(NOLOCK) ON ITM.FromItemID = SRArea1ITM.ItemID And ITM.CategoryCode = 'ST1' And ITM.Deleted != 1 left outer Join XBOLTADM.TB_ITEM ITM2 WITH(NOLOCK) ON ITM2.ItemID = ITM.ToItemID AND ITM2.Deleted != 1 left outer Join XBOLTADM.TB_ITEM_ATTR SRArea2ATR WITH(NOLOCK) ON SRArea2ATR.ItemID = ITM2.ItemID AND SRArea2ATR.AttrTypeCode = 'AT00001' and SRArea2ATR.LanguageID = ${languageID} left outer Join XBOLTADM.TB_ITEM_ATTR SRArea2T WITH(NOLOCK) ON SRArea2T.ItemID = SRArea2ATR.ItemID AND SRArea2T.AttrTypeCode = 'AT00036' and (SRArea2T.PlainText = 'ITSP' or SRArea2T.PlainText = 'CMM' or SRArea2T.PlainText = #{srType}) left outer Join XBOLTADM.TB_ITEM_ATTR SRArea2ATR2 WITH(NOLOCK) ON SRArea2ATR2.ItemID = SRArea2T.ItemID AND SRArea2ATR2.AttrTypeCode = 'AT00035' AND SRArea2ATR2.LanguageID = ${languageID} left outer join XBOLTADM.TB_ATTR_TYPE_LOV TATL2 WITH(NOLOCK) ON TATL2.AttrTypeCode = 'AT00035' AND TATL2.LovCode = SRArea2ATR2.PlainText AND TATL2.LanguageID = ${languageID}
Inner join XBOLTADM.TB_ITEM ITM3 WITH(NOLOCK) ON ITM3.ToItemID = ITM1.ItemID Inner join XBOLTADM.TB_ITEM ITM4 WITH(NOLOCK) ON ITM4.ItemID = ITM3.FromItemID Inner join XBOLTADM.TB_ITEM_ATTR Domain WITH(NOLOCK) ON Domain.ItemID = ITM4.ItemID And Domain.LanguageID = ${languageID} AND Domain.AttrTypeCode = 'AT00001'
INNER JOIN XBOLTADM.TB_MY_ITEM TIM ON TIM.ItemID = ISNULL(ITM2.ItemID,ITM1.ItemID) AND AssignmentType = 'SRROLETP' AND Assigned = 1 AND RoleType = #{roleFilter} AND TIM.MemberID = #{userID}
Where SRType.AttrTypeCode = 'AT00036'
And (SRType.PlainText = 'ITSM' OR SRType.PlainText = 'CMM' OR SRType.PlainText = #{srType}) And (SRArea2T.PlainText = 'ITSM' OR SRArea2T.PlainText = 'CMM' OR SRArea2T.PlainText = #{srType})
AND SRType.ItemID = SRArea1ITM.ItemID AND SRArea1ITM.LovCode = 'LV38001' And SRArea1ATR.AttrTypeCode = 'AT00001' And SRArea1ITM.ItemID = SRArea1ATR.ItemID and SRArea1ATR.LanguageID = ${languageID} And ITM1.Deleted != 1
And ITM1.ProjectID in ( SELECT TP.ProjectID FROM XBOLTADM.TB_PROJECT TP WITH(NOLOCK) left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR on TP.ProjectID = TPMR.ProjectID Where TPMR.MemberID = #{userID} And TP.ProjectType = 'CSR' )
AND ITM1.ClientID = #{clientID}
Order by ClientID, ITM1.Identifier, ITM2.Identifier

SELECT ESA.SpeCode, TIA.PlainText As Stsname, ESA.Value As SRAT0069, EAL.EndTime, EAL.ActorID, TM.Name + '('+ISNULL(TMT.Name,'-')+'/'+ISNULL(TMT2.Name,'-')+')' As ReceiptUserNM , EAL.Status , EAL.DocCategory
FROM XBOLTAPP.ESM_SR_ATTR ESA WITH(NOLOCK)
LEFT OUTER JOIN XBOLTAPP.ESM_ACTIVITY_LOG EAL WITH(NOLOCK) ON EAL.PID = #{srID} AND EAL.SpeCode = ESA.SpeCode AND EAL.Seq = (
						    SELECT MAX(Seq)
						    FROM XBOLTAPP.ESM_ACTIVITY_LOG
						    WHERE SpeCode = ESA.SpeCode
						    AND PID = #{srID}
						  ) AND EAL.Status IN ('05','03','02')
LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM WITH(NOLOCK) ON TM.MemberID = EAL.ActorID
LEFT OUTER JOIn XBOLTADM.TB_ITEM TI WITH(NOLOCK) ON TI.Identifier = ESA.SpeCode
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TI.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TMT WITH(NOLOCK) ON TMT.TeamID = TM.CompanyID And TMT.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TMT2 WITH(NOLOCK) ON TMT2.TeamID = TM.TeamID And TMT2.LanguageID = #{languageID}
WHERE ESA.AttrTypeCode = 'SRAT0069' AND ESA.SRID = #{srID}
ORDER BY ESA.Seq ASC

mapper.update:
Update XBOLTAPP.ESM_SERVICE_ITEM SET
	Description = #{description},
	LastUpdated = GETDATE(),
	LastUser = #{lastUser}			
Where ServiceItemID = #{serviceItemID}

mapper.select:
Select Top 1 TM.MemberID From XBOLTAPP.ESM_ACTIVITY_LOG EAL
Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = EAL.ActorID 
Where EAL.PID = #{srID}
And EAL.PrevSRCategory in (${preCategory})
And EAL.SpeCode = #{speCode}

SELECT
	Count(*) CNT
FROM 
	XBOLTAPP.ESM_SR_MST ESM
LEFT OUTER JOIN XBOLTAPP.ESM_MBR_RCD EMR ON ESM.SRID = EMR.SRID
WHERE 
	ESM.SRType = #{srType}
	 AND ESM.Status = #{speCode}
	 AND EMR.WORK_DATE IN (${workDate})
	 AND ESM.Subject = #{subject}

Select ReceiptUserID
From XBOLTAPP.ESM_SR_MST 
WHERE SRID = #{srID}

Select Top 1 ActivityLogID 
From XBOLTAPP.ESM_ACTIVITY_LOG 

    
		AND WFInstanceID = #{wfInstanceID}

	Select 
 		Count(TBD.SRID)
	From(
	 	Select
	 	 	TSM.SRID, TSM.SRCode, TSM.SRType, TSM.ESType, TD5.Name AS SRTypeNM, TSM.ProcRoleTP, TSM.Blocked,
			TEAM6.Name AS CompanyName, TSM.ClientID,TSM.ProjectID,
			TSM.Subject, TSM.SRArea1, TIA.PlainText As SRArea1Name,
			TSM.SRArea2, TIA2.PlainText As SRArea2Name,
			TSM.Category,  TD4.Name As CategoryNM,
			TSM.SubCategory, ISNULL(TD3.Name, TD4.Name) As SubCategoryNM,
			TSM.Status, TISA.PlainText As StatusName, TSM.RegUserID, TM2.Name As RegUserName,
			TSM.RegTeamID, TEAM1.Name As RegTeamName,
			ISNULL(CONVERT(char(10),TSM.RegDT, 120),'') as RegDate,				
			TSM.RequestUserID, TM3.Name As ReqUserNM,
			TSM.RequestTeamID, TEAM2.Name As ReqTeamNM,
			ISNULL(CONVERT(char(10),TSM.DueDate, 120),'') as SRDueDate,				
			ISNULL(CONVERT(char(10),TSM.ReqDueDate, 120),'') as ReqDueDate,				
			TSM.ReceiptUserID, TM4.Name As ReceiptName, 
			TSM.ReceiptTeamID, TEAM3.Name As ReceiptTeamName,
			TM4.Name + '(' + TEAM3.Name + ')' as ReceiptInfo,
			TM3.Name + '(' + TEAM2.Name + ')' as RequestInfo,
			TSM.ResponseUserID, TM5.Name As ResponseUserName,
			TSM.ResponseTeamID, TEAM4.Name As ResponseTeamName,
			TM5.Name + '(' + TEAM4.Name + ')' as ResponseInfo,
			ISNULL(CONVERT(char(10),TSM.CompletionDT, 120),'') as SRCompletionDT,
			
			TSM.RegDT As RegDTOrg,
			TSM.ReqDueDate AS ReqDueDateOrg,
			TSM.DueDate as DueDateOrg,
			TSM.CompletionDT As CompletionDTOrg,
			TSM.CompanyID,
			TSM.ReceiptTeamID As SRReceiptTeamID,
			Case When CompletionDT IS NULL Then 'N' Else 'Y' End AS SvcCompl,
		 	CompletionDelay = CASE WHEN TSM.CompletionDT is null THEN 
													CASE 
														 WHEN TSM.Duedate < GETDATE() THEN 'Y' 
														ELSE 'N'
													END
													WHEN TSM.CompletionDT is not null THEN 
														CASE 
															WHEN TSM.Duedate < tsm.CompletionDT THEN 'Y'
															ELSE 'N'
														END
													END,
			TSM.isPublic
		From XBOLTAPP.ESM_SR_MST TSM WITH(NOLOCK)
		Left Outer Join XBOLTADM.TB_MEMBER TM2 WITH(NOLOCK) On TM2.MemberID = TSM.RegUserID
		Left Outer Join XBOLTADM.TB_MEMBER TM3 WITH(NOLOCK) On TM3.MemberID = TSM.RequestUserID
		Left Outer Join XBOLTADM.TB_MEMBER TM4 WITH(NOLOCK) On TM4.MemberID = TSM.ReceiptUserID
		Left Outer Join XBOLTADM.TB_MEMBER TM5 WITH(NOLOCK) On TM5.MemberID = TSM.ResponseUserID
		Left Outer Join XBOLTADM.TB_DICTIONARY TD4 WITH(NOLOCK) On TD4.TypeCode = TSM.Category AND TD4.Category = 'SRCAT' And TD4.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD3 WITH(NOLOCK) On TD3.TypeCode = TSM.SubCategory And TD3.Category = 'SRCAT' And TD3.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM TIS WITH(NOLOCK) ON TSM.Status = TIS.Identifier
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TISA WITH(NOLOCK) ON TISA.ItemID = TIS.ItemID And TISA.AttrTypeCode = 'AT00001' And TISA.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM1 WITH(NOLOCK) ON TEAM1.TeamID = TSM.RegTeamID And TEAM1.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM2 WITH(NOLOCK) ON TEAM2.TeamID = TSM.RequestTeamID And TEAM2.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM3 WITH(NOLOCK) ON TEAM3.TeamID = TSM.ReceiptTeamID And TEAM3.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM4 WITH(NOLOCK) ON TEAM4.TeamID = TSM.ResponseTeamID And TEAM4.LanguageID = #{languageID} 
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TSM.SRArea1 And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID  =  #{languageID}
		Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = TSM.SRArea2 And TIA2.AttrTypeCode = 'AT00001' And TIA2.LanguageID  =  #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD5 WITH(NOLOCK) On TD5.TypeCode = TSM.SRType And TD5.Category = 'SRTP' And TD5.LanguageID = #{languageID}
		Left Outer Join XBOLTAPP.ESM_SR_TYPE EST WITH(NOLOCK) On EST.srtypecode = TSM.srtype
		Left Outer Join XBOLTAPP.CRM_CUST_MST CCM WITH(NOLOCK) ON TSM.ClientID = CCM.CustomerNo
		Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM6 WITH(NOLOCK) ON TEAM6.TeamID = CCM.TeamID And TEAM6.LanguageID = #{languageID}
		Left Outer Join XBOLTADM.TB_DICTIONARY TD8 WITH(NOLOCK) On TD8.TypeCode = TSM.ProcRoleTP And TD8.Category = 'SRROLETP' And TD8.LanguageID = #{languageID}			
	) AS TBD 
	
	    
			AND TBD.ESType = #{esType}
		
		
			AND TBD.SRType = #{srType}
		
		
			AND #{sessionUserID} In (RequestUserID, ReceiptUserID , RegUserID)
		
		
			AND #{sessionUserID} In ( ReceiptUserID )
		
		
			AND #{sessionUserID} In ( ReceiptUserID, ResponseUserID )
		
		
			AND #{sessionUserID} In (RequestUserID)
		
		
			AND #{sessionUserID}  In (RequestUserID, ReceiptUserID)
		
		
			AND TBD.ClientID = (Select ClientID from XBOLTADM.TB_MEMBER Where MemberID = #{sessionUserID} )
		
		
			AND TBD.SRID In (Select PID from XBOLTADM.TB_PROC_LOG where ActorID = #{sessionUserID} and ActivityID = 'ACTP003')
		
		
			AND #{myTeamId}  In (TBD.RequestTeamID, TBD.ReceiptTeamID)
		
		
			AND #{sessionUserID} In (SELECT MemberID FROM XBOLTADM.TB_MY_ITEM WHERE ItemID = TBD.SRArea2 AND Assigned = '1')
				
		
			
				
					And SvcCompl = 'N' 
				
				
					And SvcCompl = 'Y' 
				
				
				
				
					And TBD.IsPublic = 0
				
			
		
		
			AND TBD.Status = #{srStatus}
		
		
			AND TBD.Status IN (${srStatusArr})
		
		
			AND TBD.ProjectID IN (Select ProjectID From XBOLTADM.TB_PROJECT Where RefPGID = #{refID} And ProjectType = 'PJT' )
			
		
			AND TBD.ProjectID = #{refID} 
			
		
			AND TBD.ProjectID IN (Select ProjectID From XBOLTADM.TB_PJT_MEMBER_REL Where MemberID = #{sessionUserID} AND Involved = '1' )
			
		
			AND ReqUserNM like N'%'+#{requestUserName}+'%'
		
		
			AND RegUserName like N'%'+#{regUserName}+'%'
		
		
			AND ReceiptName like N'%'+#{receiptUserName}+'%'
		
		
			AND  CONVERT(varchar(10), TBD.RegDate, 120) BETWEEN #{regStartDate} AND #{regEndDate}  
		
		
			AND TBD.SRArea1 = #{srArea1}
		
		
			AND TBD.SRArea2 = #{srArea2}
		
		
			AND TBD.Category = #{category} 
		
		
			AND TBD.SubCategory = #{subCategory}
		
		
			AND  CONVERT(varchar(10), TBD.SRdueDate, 120) BETWEEN #{stSRDueDate} AND #{endSRDueDate}  
		
		
			AND  CONVERT(varchar(10), TBD.SRCompletionDT, 120) BETWEEN #{stSRCompDT} AND #{endSRCompDT}  
		
		
			AND  Convert(varchar(10),TBD.CompletionDT, 120)  <= #{completionDT}  
		
		
			AND TBD.SRCode like N'%'+#{srCode}+'%'
		
		
			AND TBD.SrID = #{srID}
		
		
			AND TBD.RequestTeamID = #{requestTeam}
		
		
			AND TBD.ResponseTeamID = #{responseTeamID}
		
		
			AND TBD.SRReceiptTeamID = #{srReceiptTeam}
		
		
			AND TBD.ReceiptDelay = #{receiptDelay}
		
		
			AND TBD.CompletionDelay = #{completionDelay}
		
		
			AND TBD.Subject like N'%'+#{subject}+'%'
		
		
			AND #{itemID}  IN (TBD.SRArea1, TBD.SRArea2, TBD.SRArea3)
		
		
			AND Classification = #{classification}
		
		
			AND TBD.RequestTeamID IN (${requestTeamList})
		
		
			AND ( TBD.CompanyID IN (${companyList}) OR TBD.RequestTeamID IN (${companyList}) )
		
		
			AND TBD.CustGRNo = #{custGRNo}
		
		
			AND TBD.ClientID = #{custNo})
		
		
			AND TBD.ClientID = #{clientID}
		
		
			AND TBD.CompanyID IN (#{companyID})
		
		
			AND TBD.ItemCode like N'%'+#{itemCode}+'%'
		
		
			AND TBD.ItemName like N'%'+#{itemName}+'%'
		
		
			AND TBD.ItemTypeCode = #{itemTypeCode}
		
		
			AND TBD.SRID in (Select ToSRID From XBOLTAPP.ESM_SR_CXN Where FromSRID = #{fromSRID})
		
		
		 
			AND (1=1
			
				
					
					${item.selectOption} TBD.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR 
									Where AttrTypeCode = #{item.attrCode}
									And ISNULL(Value,'')
									NOT
									Like replace('%'+#{item.searchValue}+'%', ' ','')
								)
					
					
					
						${item.selectOption} TBD.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR 
							Where AttrTypeCode = #{item.attrCode}
							And LovCode 
							NOT
							IN (
							
								#{item2}
							
							)
						)
						
					
								
					
						
							
							${item.selectOption} TBD.SRID IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR 
										Where AttrTypeCode = #{item.attrCode}
									)
							
							
							${item.selectOption} TBD.SRID NOT IN ( Select SRID From XBOLTAPP.ESM_SR_ATTR 
										Where AttrTypeCode = #{item.attrCode}
									)
							
						
					
				
			
			)
		
		
			And (
				TBD.SRID IN (Select SRID From XBOLTAPP.ESM_MBR_RCD Where SRID = TBD.SRID And MemberID = #{sessionUserID} AND SpeCode = TBD.Status ) 
				OR ( #{sessionUserID} In ( TBD.ReceiptUserID ) AND TBD.Blocked = 0 AND TBD.ProcRoleTP != 'CLIENT' AND TBD.ProcRoleTP IS NOT NULL )
			)
		
		
			And TBD.ProcRoleTP IN (Select RoleType From XBOLTADM.TB_MY_ITEM Where ItemID = TBD.SRArea2 AND Assigned = '1' And MemberID = #{sessionUserID})
		
		
			And TBD.SRID IN ( Select PID From XBOLTAPP.ESM_ACTIVITY_LOG Where ActorID = #{sessionUserID} )
		
		
			And TBD.ProjectID in (
				SELECT TP.ProjectID
				FROM XBOLTADM.TB_PROJECT TP
				left outer join XBOLTADM.TB_PJT_MEMBER_REL TPMR on TP.ProjectID = TPMR.ProjectID
				Where TPMR.MemberID = #{sessionUserID}
				And TP.ProjectType = 'CSR'
			)

	Select TORT.RoleTypeCode, TD.Name As RoleTypeNM , TIA.PlainText CompanyNM, TIA1.PlainText SRArea1NM, TIA2.PlainText SRArea2NM, TI.ItemID
	From XBOLTADM.TB_OLM_ROLE_TYPE TORT WITH(NOLOCK)
	Left Outer Join XBOLTADM.TB_DICTIONARY TD WITH(NOLOCK) ON TD.TypeCode = TORT.RoleTypeCode And TD.LanguageID = #{languageID} And TD.Category = #{assignmentType}
	
	
		
			Left Outer Join XBOLTADM.TB_MY_ITEM TMI WITH(NOLOCK) ON TMI.AssignmentType = #{assignmentType} AND TMI.RoleType = TORT.RoleTypeCode AND TMI.MemberID = #{searchUserID}
			LEFT OUTER JOIN XBOLTADM.TB_ITEM TI WITH(NOLOCK) ON TI.ItemID = TMI.ITemID
			Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = TMI.ItemID AND TIA2.AttrTypeCode = 'AT00001' AND TIA2.LanguageID = #{languageID} AND TIA2.ClassCode = 'CL04002'
			Left Outer Join XBOLTADM.TB_ITEM TIAP WITH(NOLOCK) ON TIAP.ToItemID = TMI.ItemID
			Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA1 WITH(NOLOCK) ON TIA1.ItemID = ( CASE WHEN TI.ClassCode = 'CL04002' THEN TIAP.fromItemID ELSE TMI.ItemID END ) AND TIA1.AttrTypeCode = 'AT00001' AND TIA1.LanguageID = #{languageID} AND TIA1.ClassCode = 'CL04001'
			Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = ( SELECT fromItemID From XBOLTADM.TB_ITEM WHERE toItemID = TI.ItemID) AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
		
		
			Left Outer Join XBOLTADM.TB_ITEM TI WITH(NOLOCK) ON TI.ItemID = #{itemID}
			Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA1 WITH(NOLOCK) ON TIA1.ItemID = #{srArea1} AND TIA1.AttrTypeCode = 'AT00001' AND TIA1.LanguageID = #{languageID} AND TIA1.ClassCode = 'CL04001'
			Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = #{srArea2} AND TIA2.AttrTypeCode = 'AT00001' AND TIA2.LanguageID = #{languageID} AND TIA2.ClassCode = 'CL04002'
			Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = ( SELECT fromItemID From XBOLTADM.TB_ITEM WHERE toItemID = #{srArea1}) AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
		
	
	
	
			
 		
			TORT.ProcessType = #{srType}
		
 		
			AND TORT.AssignmentType = #{assignmentType}
		
		
			AND TMI.MemberID IS NOT NULL
			
				AND TMI.ItemID = ${itemID}
			
		
		
	
	GROUP BY TORT.RoleTypeCode, TD.Name, TD.SortNum, TD.TypeCode, TI.ItemID , TIA.PlainText, TIA1.PlainText, TIA2.PlainText
	order by TD.SortNum, TD.TypeCode

